def _ai_validate_automation_operation(operation: dict) -> tuple[dict | None, list[dict]]:
    errors: list[dict] = []
    if not isinstance(operation, dict):
        return None, [{"code": "AI_PATCH_OP_INVALID", "message": "operation must be object", "path": "operation"}]
    op_name = operation.get("op")
    artifact_id = operation.get("artifact_id") if isinstance(operation.get("artifact_id"), str) and operation.get("artifact_id").strip() else None
    if not isinstance(op_name, str) or op_name not in {"create_automation_record", "update_automation_record"}:
        return None, [{"code": "AI_PATCH_OP_UNSUPPORTED", "message": "unsupported automation op", "path": "operation.op"}]
    if not isinstance(artifact_id, str) or not artifact_id:
        return None, [{"code": "AI_PATCH_OP_INVALID", "message": "automation operation requires artifact_id", "path": "operation.artifact_id"}]
    payload = operation.get("automation")
    if not isinstance(payload, dict):
        errors.append({"code": "AI_PATCH_OP_INVALID", "message": "automation payload is required", "path": "operation.automation"})
        return None, errors
    normalized = copy.deepcopy(payload)
    normalized["id"] = artifact_id
    validation_errors = _validate_automation_payload(normalized, for_update=(op_name == "update_automation_record"))
    if validation_errors:
        return None, [
            {
                "code": "AUTOMATION_INVALID",
                "message": item.get("message") if isinstance(item, dict) else "Invalid automation payload",
                "path": item.get("path") if isinstance(item, dict) else "operation.automation",
                "detail": item if isinstance(item, dict) else None,
            }
            for item in validation_errors
        ]
    return normalized, []


def _ai_automation_summary_line(op: dict) -> str | None:
    if not isinstance(op, dict):
        return None
    automation = op.get("automation") if isinstance(op.get("automation"), dict) else {}
    name = automation.get("name") if isinstance(automation.get("name"), str) and automation.get("name").strip() else None
    trigger = automation.get("trigger") if isinstance(automation.get("trigger"), dict) else {}
    steps = automation.get("steps") if isinstance(automation.get("steps"), list) else []
    event_types = [item for item in (trigger.get("event_types") or []) if isinstance(item, str) and item.strip()]
    first_step = steps[0] if steps and isinstance(steps[0], dict) else {}
    action_id = first_step.get("action_id") if isinstance(first_step.get("action_id"), str) else None
    recipient = None
    if isinstance(first_step.get("inputs"), dict):
        to_value = first_step["inputs"].get("to")
        if isinstance(to_value, str) and to_value.strip():
            recipient = to_value.strip()
    event_label = None
    if event_types:
        event_label = event_types[0]
        if event_label == "workflow.status_changed":
            event_label = "workflow status changes"
    if op.get("op") == "create_automation_record":
        if name and recipient and action_id == "system.send_email" and event_label:
            return f"Create automation '{name}' to email {recipient} when {event_label}."
        if name and event_label:
            return f"Create automation '{name}' for {event_label}."
        if name:
            return f"Create automation '{name}'."
        return "Create a new automation."
    if op.get("op") == "update_automation_record":
        if name:
            return f"Update automation '{name}'."
        return "Update the automation."
    return None


def _ai_apply_automation_record(operation: dict, *, publish: bool, actor_id: str | None = None) -> tuple[dict | None, list[dict]]:
    errors: list[dict] = []
    normalized, validation_errors = _ai_validate_automation_operation(operation)
    if validation_errors:
        return None, validation_errors
    op_name = operation.get("op")
    automation_id = normalized.get("id")
    existing = automation_store.get(automation_id) if automation_store else None
    if op_name == "create_automation_record":
        if existing:
            updated = automation_store.update(automation_id, normalized) if automation_store else None
            item = updated
        else:
            item = automation_store.create(normalized) if automation_store else None
    else:
        if not existing:
            return None, [{"code": "AUTOMATION_NOT_FOUND", "message": "automation not found", "path": "operation.artifact_id"}]
        item = automation_store.update(automation_id, normalized) if automation_store else None
    if not isinstance(item, dict):
        return None, [{"code": "AUTOMATION_APPLY_FAILED", "message": "failed to persist automation", "path": "operation"}]
    if publish:
        item = automation_store.update(
            automation_id,
            {
                "status": "published",
                "published_at": _now(),
                "published_by": actor_id,
            },
        ) if automation_store else None
        if not isinstance(item, dict):
            return None, [{"code": "AUTOMATION_PUBLISH_FAILED", "message": "failed to publish automation", "path": "operation"}]
    return item, []


def _ai_automation_record_version(item: dict | None) -> str | None:
    if not isinstance(item, dict):
        return None
    for key in ("updated_at", "published_at", "created_at"):
        value = item.get(key)
        if isinstance(value, str) and value.strip():
            return value
    return None


def _ai_missing_snapshot_payload() -> dict:
    return {"__ai_missing__": True}


def _ai_snapshot_represents_missing(snapshot_json: Any) -> bool:
    return isinstance(snapshot_json, dict) and snapshot_json.get("__ai_missing__") is True


def _ai_build_workflow_comment_requirement_spec(
    manifest: dict,
    module_id: str,
    entity_id: str,
    status_field_id: str,
    status_options: list[dict],
    message: str,
    existing_ops: list[dict] | None = None,
) -> dict | None:
    requirement = _ai_extract_workflow_comment_requirement(message)
    if not isinstance(requirement, dict):
        return None
    entity = _ai_find_entity_by_id(manifest, entity_id)
    if not isinstance(entity, dict):
        return None

    target_values: list[str] = []
    target_labels: list[str] = []
    for target in requirement.get("targets") or []:
        if not isinstance(target, dict):
            continue
        label = target.get("label") if isinstance(target.get("label"), str) and target.get("label").strip() else None
        aliases = {
            _ai_norm_token(alias)
            for alias in (target.get("aliases") or set())
            if isinstance(alias, str) and _ai_norm_token(alias)
        }
        if isinstance(label, str) and label:
            target_labels.append(label)
        matched_value = None
        for option in status_options:
            if not isinstance(option, dict):
                continue
            value = option.get("value") if isinstance(option.get("value"), str) and option.get("value").strip() else None
            option_label = option.get("label") if isinstance(option.get("label"), str) and option.get("label").strip() else None
            candidates = {
                _ai_norm_token(value) if isinstance(value, str) else "",
                _ai_norm_token(option_label) if isinstance(option_label, str) else "",
            }
            if any(candidate and candidate in aliases for candidate in candidates):
                matched_value = value
                break
        if isinstance(matched_value, str) and matched_value and matched_value not in target_values:
            target_values.append(matched_value)

    field_label = requirement.get("field_label") if isinstance(requirement.get("field_label"), str) and requirement.get("field_label").strip() else "Decision Comments"
    if not target_values:
        status_phrase = _ai_join_human_list(target_labels) if target_labels else "the requested approval status"
        return {
            "ops": [],
            "field_label": field_label,
            "status_values": [],
            "status_phrase": status_phrase,
            "assumptions": [],
            "advisories": [f"I couldn't match the requested comment rule to an existing lifecycle status for {status_phrase}."],
        }

    required_when = (
        {"op": "eq", "field": status_field_id, "value": target_values[0]}
        if len(target_values) == 1
        else {"op": "in", "field": status_field_id, "value": target_values}
    )
    status_phrase = _ai_join_human_list([_ai_titleize_slug(value) for value in target_values])
    field_candidates = [
        field_label,
        "Decision Comments",
        "Manager Comments",
        "Rejection Comments",
        "Approval Comments",
        "Comments",
        "Notes",
    ]
    existing_field = next(
        (
            field
            for candidate in field_candidates
            for field in [_ai_match_field_in_entity(entity, candidate)]
            if isinstance(field, dict)
        ),
        None,
    )

    ops: list[dict] = []
    all_ops = [copy.deepcopy(op) for op in (existing_ops or []) if isinstance(op, dict)]
    assumptions = ["The comments field will stay visible on the form so staff can complete it before using the workflow buttons."]
    advisories = [f"'{field_label}' will become required when the record is {status_phrase}."]
    if isinstance(existing_field, dict) and isinstance(existing_field.get("id"), str):
        field_id = existing_field.get("id")
        if existing_field.get("required_when") != required_when:
            ops.append(
                {
                    "op": "update_field",
                    "artifact_type": "module",
                    "artifact_id": module_id,
                    "field_id": field_id,
                    "changes": {"required_when": required_when},
                }
            )
        all_ops.extend(ops)
        if not _ai_find_form_field_location(manifest, field_id) and not any(_ai_op_includes_form_field(op, module_id, field_id) for op in all_ops):
            ops.extend(
                _ai_build_placement_ops_for_field(
                    manifest,
                    module_id,
                    entity_id,
                    field_id,
                    existing_field.get("label") if isinstance(existing_field.get("label"), str) and existing_field.get("label").strip() else field_label,
                    include_form=True,
                    include_list=False,
                    existing_ops=[*all_ops, *ops],
                )
            )
        return {
            "ops": ops,
            "field_label": existing_field.get("label") if isinstance(existing_field.get("label"), str) and existing_field.get("label").strip() else field_label,
            "status_values": target_values,
            "status_phrase": status_phrase,
            "assumptions": assumptions if ops else [],
            "advisories": advisories if ops else [],
        }

    entity_tail = entity_id.split(".")[-1]
    field_slug = _marketplace_slugify(field_label).replace("-", "_").strip("_") or "decision_comments"
    field_id = f"{entity_tail}.{field_slug}"
    existing_field_ids = {
        field.get("id")
        for field in (entity.get("fields") or [])
        if isinstance(field, dict) and isinstance(field.get("id"), str)
    }
    suffix = 2
    while field_id in existing_field_ids:
        field_id = f"{entity_tail}.{field_slug}_{suffix}"
        suffix += 1
    ops.append(
        {
            "op": "add_field",
            "artifact_type": "module",
            "artifact_id": module_id,
            "entity_id": entity_id,
            "field": {
                "id": field_id,
                "label": field_label,
                "type": "text",
                "required_when": required_when,
            },
        }
    )
    ops.extend(
        _ai_build_placement_ops_for_field(
            manifest,
            module_id,
            entity_id,
            field_id,
            field_label,
            include_form=True,
            include_list=False,
            existing_ops=[*all_ops, *ops],
        )
    )
    return {
        "ops": ops,
        "field_label": field_label,
        "status_values": target_values,
        "status_phrase": status_phrase,
        "assumptions": assumptions,
        "advisories": advisories,
    }


def _ai_build_workflow_action_sync_ops(manifest: dict, module_id: str, entity_id: str, workflow_override: dict | None = None) -> tuple[list[dict], list[str]]:
    if not isinstance(manifest, dict) or not isinstance(module_id, str) or not module_id or not isinstance(entity_id, str) or not entity_id:
        return [], ["Workflow context is incomplete."]
    workflow = workflow_override if isinstance(workflow_override, dict) else next(
        (
            item
            for item in (manifest.get("workflows") or [])
            if isinstance(item, dict)
            and item.get("entity") == entity_id
            and isinstance(item.get("status_field"), str)
        ),
        None,
    )
    if not isinstance(workflow, dict):
        return [], ["I couldn't find an existing lifecycle workflow to wire action buttons from."]
    status_field_id = workflow.get("status_field")
    if not isinstance(status_field_id, str) or not status_field_id:
        return [], ["The workflow is missing its status field."]

    entity_slug = entity_id.split(".")[-1]
    target_actions = _ai_status_actions_for_workflow(entity_slug, entity_id, status_field_id, workflow)
    if not target_actions:
        return [], ["I couldn't derive any status transitions from the current workflow."]

    ops: list[dict] = []
    existing_actions = {
        action.get("id"): action
        for action in (manifest.get("actions") or [])
        if isinstance(action, dict) and isinstance(action.get("id"), str)
    }
    action_ids: list[str] = []
    for target_action in target_actions:
        action_id = target_action.get("id")
        if not isinstance(action_id, str) or not action_id:
            continue
        action_ids.append(action_id)
        current_action = existing_actions.get(action_id)
        if current_action is None:
            ops.append({"op": "add_action", "artifact_type": "module", "artifact_id": module_id, "action": copy.deepcopy(target_action)})
        elif current_action != target_action:
            changes = copy.deepcopy(target_action)
            changes.pop("id", None)
            ops.append(
                {
                    "op": "update_action",
                    "artifact_type": "module",
                    "artifact_id": module_id,
                    "action_id": action_id,
                    "changes": changes,
                }
            )

    form_view, _list_view = _ai_find_form_and_list_views(manifest, entity_id)
    if isinstance(form_view, dict) and isinstance(form_view.get("id"), str):
        header = copy.deepcopy(form_view.get("header") if isinstance(form_view.get("header"), dict) else {})
        changed = False
        if header.get("statusbar") != {"field_id": status_field_id}:
            header["statusbar"] = {"field_id": status_field_id}
            changed = True
        secondary_actions = [item for item in (header.get("secondary_actions") or []) if isinstance(item, dict)]
        for action_id in action_ids:
            if not any(existing.get("action_id") == action_id for existing in secondary_actions if isinstance(existing, dict)):
                secondary_actions.append({"action_id": action_id})
                changed = True
        if changed:
            header["secondary_actions"] = secondary_actions
            ops.append(
                {
                    "op": "update_view",
                    "artifact_type": "module",
                    "artifact_id": module_id,
                    "view_id": form_view.get("id"),
                    "changes": {"header": header},
                }
            )

    if not ops:
        return [], ["Workflow action buttons are already wired from the current lifecycle states."]
    return ops, []


def _ai_is_greeting_only(text: str) -> bool:
    normalized = _ai_norm_token(text)
    if not normalized:
        return False
    return normalized in {
        "hi",
        "hey",
        "hello",
        "hiya",
        "yo",
        "good morning",
        "good afternoon",
        "good evening",
        "hey there",
        "hello there",
    }


def _ai_extra_fields_from_prompt(entity_slug: str, message: str) -> list[dict]:
    lower = (message or "").lower()
    fields: list[dict] = []

    def add(field_id: str, field_type: str, label: str, **extra) -> None:
        field = {"id": f"{entity_slug}.{field_id}", "type": field_type, "label": label}
        field.update(extra)
        fields.append(field)

    keyword_fields = [
        (("course", "courses"), ("course_name", "string", "Course")),
        (("customer", "client"), ("client_name", "string", "Client")),
        (("supplier",), ("supplier_name", "string", "Supplier")),
        (("provider",), ("provider_name", "string", "Provider")),
        (("company",), ("company_name", "string", "Company")),
        (("vehicle",), ("vehicle_name", "string", "Vehicle")),
        (("driver",), ("driver_name", "string", "Driver")),
        (("host",), ("host_name", "string", "Host")),
        (("employee",), ("employee_name", "string", "Employee")),
        (("requester",), ("requester_name", "string", "Requester")),
        (("manager",), ("manager_name", "string", "Manager")),
        (("auditor",), ("auditor_name", "string", "Auditor")),
        (("attendees",), ("attendees", "text", "Attendees")),
        (("people involved",), ("people_involved", "text", "People Involved")),
        (("route",), ("route", "string", "Route")),
        (("location",), ("location", "string", "Location")),
        (("outcome",), ("outcome", "text", "Outcome")),
        (("category",), ("category", "string", "Category")),
        (("leave type",), ("leave_type", "string", "Leave Type")),
        (("focus", "focus area"), ("focus_area", "string", "Focus Area")),
        (("summary",), ("summary", "text", "Summary")),
        (("finding", "finding summary"), ("finding_summary", "text", "Finding Summary")),
        (("certificate", "certificates"), ("certificate_reference", "string", "Certificate Reference")),
        (("follow up", "follow-up"), ("follow_up", "text", "Follow Up")),
        (("decision", "decisions"), ("decision_notes", "text", "Decision Notes")),
    ]
    for tokens, spec in keyword_fields:
        if any(token in lower for token in tokens):
            add(*spec)

    numeric_fields = [
        (("amount",), ("amount", "number", "Amount")),
        (("cost",), ("cost", "number", "Cost")),
        (("score",), ("score", "number", "Score")),
        (("variance",), ("variance", "number", "Variance")),
        (("litres", "liters"), ("litres", "number", "Litres")),
        (("odometer",), ("odometer", "number", "Odometer")),
        (("duration",), ("duration_minutes", "number", "Duration (Minutes)")),
    ]
    for tokens, spec in numeric_fields:
        if any(token in lower for token in tokens):
            add(*spec)

    if "severity" in lower:
        add(
            "severity",
            "enum",
            "Severity",
            options=[
                {"label": "Low", "value": "low"},
                {"label": "Medium", "value": "medium"},
                {"label": "High", "value": "high"},
                {"label": "Critical", "value": "critical"},
            ],
        )
    if "priority" in lower:
        add(
            "priority",
            "enum",
            "Priority",
            options=[
                {"label": "Low", "value": "low"},
                {"label": "Medium", "value": "medium"},
                {"label": "High", "value": "high"},
                {"label": "Urgent", "value": "urgent"},
            ],
        )
    if "condition" in lower:
        add(
            "condition",
            "enum",
            "Condition",
            options=[
                {"label": "Good", "value": "good"},
                {"label": "Fair", "value": "fair"},
                {"label": "Needs Attention", "value": "needs_attention"},
            ],
        )
    if any(token in lower for token in ("receipt", "certificate", "attachment", "photo", "image", "file")):
        add("attachments", "attachments", "Attachments")
    if any(token in lower for token in ("date", "visit date", "meeting date", "check date")):
        add("event_date", "date", "Date")
    if any(token in lower for token in ("start date", "from date", "date start")):
        add("start_date", "date", "Start Date")
    if any(token in lower for token in ("end date", "to date")):
        add("end_date", "date", "End Date")
    if "due date" in lower or "expiry" in lower or "expires" in lower:
        add("due_date", "date", "Due Date")
    if any(token in lower for token in ("completion date", "completed date")):
        add("completed_date", "date", "Completed Date")
    if any(token in lower for token in ("reminder", "reminders", "expiry reminder", "expiry reminders")):
        add("reminder_date", "date", "Reminder Date")
    if any(token in lower for token in ("visit time", "meeting time", "sign out")):
        add("event_time", "datetime", "Event Time")
    return fields


def _ai_extract_requested_feature_phrases(message: str) -> list[str]:
    if not isinstance(message, str) or not message.strip():
        return []
    normalized = re.sub(r"\s+", " ", message.strip())
    patterns = (
        r"\bwith\b (?P<body>.+?)(?:[.?!]|$)",
        r"\bincluding\b (?P<body>.+?)(?:[.?!]|$)",
        r"\binclude\b (?P<body>.+?)(?:[.?!]|$)",
        r"\bfeaturing\b (?P<body>.+?)(?:[.?!]|$)",
    )
    captured: list[str] = []
    for pattern in patterns:
        match = re.search(pattern, normalized, flags=re.IGNORECASE)
        if not match:
            continue
        body = match.group("body").strip(" ,.;:")
        if body:
            captured.append(body)
    if not captured:
        return []

    phrases: list[str] = []
    for body in captured:
        parts = re.split(r",|\band\b", body, flags=re.IGNORECASE)
        for raw_part in parts:
            phrase = raw_part.strip(" ,.;:")
            phrase = re.sub(r"^(a|an|the)\s+", "", phrase, flags=re.IGNORECASE)
            phrase = re.sub(r"\s+", " ", phrase).strip()
            if not phrase:
                continue
            token_count = len([token for token in phrase.split(" ") if token])
            if token_count > 8:
                continue
            if phrase.lower() in {"it", "that", "this", "those", "these"}:
                continue
            if phrase not in phrases:
                phrases.append(phrase)
    return phrases[:8]


def _ai_sectioned_form_for_entity(entity_slug: str, fields: list[dict]) -> tuple[list[dict], dict | None]:
    field_ids = [
        field.get("id")
        for field in fields
        if isinstance(field, dict)
        and isinstance(field.get("id"), str)
        and not field.get("id").endswith(".id")
        and not field.get("id").endswith(".created_at")
    ]
    overview: list[str] = []
    planning: list[str] = []
    people: list[str] = []
    metrics: list[str] = []
    notes: list[str] = []

    for field_id in field_ids:
        tail = field_id.split(".")[-1]
        if tail in {"notes", "attachments", "summary", "finding_summary", "follow_up", "decision_notes"}:
            notes.append(field_id)
        elif any(token in tail for token in ("date", "time", "due", "start", "end", "expiry", "completed")):
            planning.append(field_id)
        elif any(token in tail for token in ("client", "customer", "supplier", "provider", "company", "vehicle", "driver", "host", "employee", "requester", "manager", "auditor", "owner", "assignee", "attendees", "people")):
            people.append(field_id)
        elif any(token in tail for token in ("amount", "cost", "score", "variance", "litres", "odometer", "duration", "priority", "severity", "condition")):
            metrics.append(field_id)
        else:
            overview.append(field_id)

    sections: list[dict] = []
    tabs: list[dict] = []

    def add_section(section_id: str, title: str, items: list[str], tab_id: str | None = None, tab_label: str | None = None) -> None:
        unique_items = []
        seen_items: set[str] = set()
        for item in items:
            if item not in seen_items:
                unique_items.append(item)
                seen_items.add(item)
        if not unique_items:
            return
        sections.append({"id": section_id, "title": title, "fields": unique_items, "layout": "columns", "columns": 2})
        if tab_id and tab_label:
            for tab in tabs:
                if tab.get("id") == tab_id:
                    tab.setdefault("sections", []).append(section_id)
                    return
            tabs.append({"id": tab_id, "label": tab_label, "sections": [section_id]})

    add_section("overview", "Overview", overview, "overview_tab", "Overview")
    add_section("planning", "Planning", planning, "planning_tab", "Planning")
    add_section("people", "People & Context", people, "planning_tab", "Planning")
    add_section("metrics", "Tracking", metrics, "tracking_tab", "Tracking")
    add_section("notes", "Notes & Files", notes, "notes_tab", "Notes")

    tabs_cfg = None
    if len(tabs) > 1:
        tabs_cfg = {"tabs": tabs, "style": "lifted", "default_tab": tabs[0].get("id")}
    return sections, tabs_cfg


def _ai_enrich_single_entity_scaffold(manifest: dict, family: str, message: str) -> dict:
    if not isinstance(manifest, dict):
        return manifest
    entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    entity = entities[0] if len(entities) == 1 and isinstance(entities[0], dict) else None
    if not isinstance(entity, dict):
        return manifest
    entity_id = entity.get("id")
    fields = entity.get("fields") if isinstance(entity.get("fields"), list) else []
    if not isinstance(entity_id, str) or not fields:
        return manifest
    entity_slug = entity_id.split(".")[-1]
    display_field = entity.get("display_field") if isinstance(entity.get("display_field"), str) else f"{entity_slug}.name"
    status_field = next((field for field in fields if isinstance(field, dict) and field.get("id") == f"{entity_slug}.status"), None)
    status_field_id = status_field.get("id") if isinstance(status_field, dict) and isinstance(status_field.get("id"), str) else None
    status_options = status_field.get("options") if isinstance(status_field, dict) and isinstance(status_field.get("options"), list) else []
    date_fields = [
        field.get("id")
        for field in fields
        if isinstance(field, dict)
        and isinstance(field.get("id"), str)
        and field.get("type") in {"date", "datetime"}
        and not str(field.get("id")).endswith(".created_at")
    ]
    owner_field_id = next(
        (
            field.get("id")
            for field in fields
            if isinstance(field, dict)
            and isinstance(field.get("id"), str)
            and field.get("type") == "user"
        ),
        None,
    )
    attachment_field_id = next(
        (
            field.get("id")
            for field in fields
            if isinstance(field, dict)
            and isinstance(field.get("id"), str)
            and field.get("type") == "attachments"
        ),
        None,
    )
    priority_like = next(
        (
            field.get("id")
            for field in fields
            if isinstance(field, dict)
            and isinstance(field.get("id"), str)
            and any(token in field.get("id", "") for token in ("priority", "severity", "condition"))
        ),
        None,
    )

    views = manifest.get("views") if isinstance(manifest.get("views"), list) else []
    form_view = next((view for view in views if isinstance(view, dict) and view.get("kind") == "form" and view.get("entity") == entity_id), None)
    list_view = next((view for view in views if isinstance(view, dict) and view.get("kind") == "list" and view.get("entity") == entity_id), None)
    calendar_view = next((view for view in views if isinstance(view, dict) and view.get("kind") == "calendar" and view.get("entity") == entity_id), None)
    if isinstance(form_view, dict):
        header = copy.deepcopy(form_view.get("header") if isinstance(form_view.get("header"), dict) else {})
        if status_field_id:
            header["statusbar"] = {"field_id": status_field_id}
        sections, tabs_cfg = _ai_sectioned_form_for_entity(entity_slug, fields)
        if sections:
            form_view["sections"] = sections
        if tabs_cfg:
            header["tabs"] = tabs_cfg
        form_view["header"] = header

    default_list_mode = _ai_design_family_default_list_mode(family)
    if default_list_mode:
        pages = manifest.get("pages") if isinstance(manifest.get("pages"), list) else []
        list_page = next((page for page in pages if isinstance(page, dict) and str(page.get("id", "")).endswith(".list_page")), None)
        if isinstance(list_page, dict):
            content = list_page.get("content") if isinstance(list_page.get("content"), list) else []
            if content and isinstance(content[0], dict):
                card = content[0]
                card_content = card.get("content") if isinstance(card.get("content"), list) else []
                if card_content and isinstance(card_content[0], dict):
                    card_content[0]["default_mode"] = default_list_mode

    interfaces: dict[str, list[dict]] = {}
    if date_fields:
        interfaces["schedulable"] = [
            {
                "entity_id": entity_id,
                "enabled": True,
                "scope": "module_and_global",
                "title_field": display_field,
                "date_start": date_fields[0],
                "date_end": date_fields[1] if len(date_fields) > 1 else date_fields[0],
                **({"owner_field": owner_field_id} if isinstance(owner_field_id, str) else {}),
                **({"status_field": status_field_id} if isinstance(status_field_id, str) else {}),
                **({"color_field": owner_field_id} if isinstance(owner_field_id, str) else {}),
            }
        ]
    if isinstance(attachment_field_id, str):
        interfaces["documentable"] = [
            {
                "entity_id": entity_id,
                "enabled": True,
                "scope": "module_and_global",
                "attachment_field": attachment_field_id,
                "title_field": display_field,
                **({"owner_field": owner_field_id} if isinstance(owner_field_id, str) else {}),
                **({"category_field": status_field_id} if isinstance(status_field_id, str) else {}),
                "date_field": f"{entity_slug}.created_at",
                "record_label_field": display_field,
                "preview_enabled": True,
                "allow_delete": True,
                "allow_download": True,
            }
        ]
    group_bys = [item for item in (status_field_id, priority_like, owner_field_id) if isinstance(item, str)]
    interfaces["dashboardable"] = [
        {
            "entity_id": entity_id,
            "enabled": True,
            "scope": "module_and_global",
            "date_field": f"{entity_slug}.created_at",
            "measures": ["count"],
            "group_bys": group_bys or [display_field],
            "default_widgets": [
                {
                    "id": f"{entity_slug}_by_status" if isinstance(status_field_id, str) else f"{entity_slug}_overview",
                    "type": "group",
                    "title": "By Status" if isinstance(status_field_id, str) else "Overview",
                    "group_by": status_field_id if isinstance(status_field_id, str) else display_field,
                    "measure": "count",
                }
            ],
        }
    ]
    manifest["interfaces"] = interfaces

    if isinstance(status_field_id, str) and status_options:
        manifest["workflows"] = _ai_build_workflow_for_status(entity_id, status_field_id, status_options)
    else:
        manifest["workflows"] = []
    manifest.setdefault("queries", {})
    workflow = (manifest.get("workflows") or [None])[0]

    actions = [copy.deepcopy(action) for action in (manifest.get("actions") or []) if isinstance(action, dict)]
    if isinstance(workflow, dict) and isinstance(status_field_id, str):
        for action in _ai_status_actions_for_workflow(entity_slug, entity_id, status_field_id, workflow):
            action_id = action.get("id")
            if isinstance(action_id, str) and not any(existing.get("id") == action_id for existing in actions if isinstance(existing, dict)):
                actions.append(action)
    manifest["actions"] = actions

    if isinstance(form_view, dict):
        header = form_view.get("header") if isinstance(form_view.get("header"), dict) else {}
        secondary_actions = [item for item in (header.get("secondary_actions") or []) if isinstance(item, dict)]
        for action in actions:
            action_id = action.get("id") if isinstance(action, dict) else None
            if not isinstance(action_id, str) or not action_id.startswith(f"action.{entity_slug}_") or action.get("kind") != "update_record":
                continue
            if not any(existing.get("action_id") == action_id for existing in secondary_actions if isinstance(existing, dict)):
                secondary_actions.append({"action_id": action_id})
        if secondary_actions:
            header["secondary_actions"] = secondary_actions
            form_view["header"] = header

    if isinstance(calendar_view, dict):
        pages = manifest.get("pages") if isinstance(manifest.get("pages"), list) else []
        app_cfg = manifest.get("app") if isinstance(manifest.get("app"), dict) else {}
        nav = app_cfg.get("nav") if isinstance(app_cfg.get("nav"), list) else []
        if not any(isinstance(page, dict) and page.get("id") == f"{entity_slug}.calendar_page" for page in pages):
            default_filter_id = None
            if isinstance(list_view, dict):
                header = list_view.get("header") if isinstance(list_view.get("header"), dict) else {}
                filters = header.get("filters") if isinstance(header.get("filters"), list) else []
                if filters and isinstance(filters[0], dict) and isinstance(filters[0].get("id"), str):
                    default_filter_id = filters[0].get("id")
            pages.append(
                {
                    "id": f"{entity_slug}.calendar_page",
                    "title": f"{entity.get('label') or _ai_titleize_slug(entity_slug)} Calendar",
                    "layout": "single",
                    "header": {"variant": "none"},
                    "content": [
                        {
                            "kind": "container",
                            "variant": "card",
                            "content": [
                                {
                                    "kind": "view_modes",
                                    "entity_id": entity_id,
                                    "default_mode": "calendar",
                                    "modes": [
                                        {"mode": "calendar", "target": f"view:{calendar_view.get('id')}"},
                                        {"mode": "list", "target": f"view:{list_view.get('id')}"} if isinstance(list_view, dict) else None,
                                        {"mode": "graph", "target": f"view:{entity_slug}.graph"},
                                        {"mode": "pivot", "target": f"view:{list_view.get('id')}", "default_group_by": status_field_id or date_fields[0]} if isinstance(list_view, dict) else None,
                                    ],
                                    **({"default_filter_id": default_filter_id} if isinstance(default_filter_id, str) else {}),
                                }
                            ],
                        }
                    ],
                }
            )
            pages[-1]["content"][0]["content"][0]["modes"] = [mode for mode in pages[-1]["content"][0]["content"][0]["modes"] if isinstance(mode, dict)]
            manifest["pages"] = pages
        if nav and isinstance(nav[0], dict):
            items = nav[0].get("items") if isinstance(nav[0].get("items"), list) else []
            if not any(isinstance(item, dict) and item.get("to") == f"page:{entity_slug}.calendar_page" for item in items):
                items.append({"label": "Calendar", "to": f"page:{entity_slug}.calendar_page"})
                nav[0]["items"] = items
                app_cfg["nav"] = nav
                manifest["app"] = app_cfg

    return manifest


def _ai_apply_design_spec_to_manifest(manifest: dict, design_spec: dict) -> dict:
    if not isinstance(manifest, dict) or not isinstance(design_spec, dict):
        return manifest
    entity_slug = design_spec.get("entity_slug") if isinstance(design_spec.get("entity_slug"), str) else None
    if not isinstance(entity_slug, str) or not entity_slug:
        return manifest
    views = manifest.get("views") if isinstance(manifest.get("views"), list) else []
    form_view = next((view for view in views if isinstance(view, dict) and view.get("id") == f"{entity_slug}.form"), None)
    if isinstance(form_view, dict):
        layout = design_spec.get("layout") if isinstance(design_spec.get("layout"), dict) else {}
        sections = [copy.deepcopy(section) for section in (layout.get("sections") or []) if isinstance(section, dict)]
        tabs = [copy.deepcopy(tab) for tab in (layout.get("tabs") or []) if isinstance(tab, dict)]
        if sections:
            form_view["sections"] = sections
        if tabs:
            header = copy.deepcopy(form_view.get("header") if isinstance(form_view.get("header"), dict) else {})
            header["tabs"] = {
                "tabs": tabs,
                "style": "lifted",
                "default_tab": layout.get("default_tab") if isinstance(layout.get("default_tab"), str) else tabs[0].get("id"),
            }
            form_view["header"] = header
    page_specs = {
        page.get("id"): page
        for page in ((design_spec.get("experience") or {}).get("pages") or [])
        if isinstance(page, dict) and isinstance(page.get("id"), str)
    }
    for page in manifest.get("pages") if isinstance(manifest.get("pages"), list) else []:
        if not isinstance(page, dict):
            continue
        spec = page_specs.get(page.get("id"))
        if isinstance(spec, dict) and isinstance(spec.get("title"), str) and spec.get("title").strip():
            page["title"] = spec.get("title").strip()
    return manifest


def _ai_add_design_related_entity_scaffolds(manifest: dict, module_id: str, design_spec: dict) -> dict:
    if not isinstance(manifest, dict):
        return manifest
    entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    primary_entity = entities[0] if entities and isinstance(entities[0], dict) else None
    primary_entity_id = primary_entity.get("id") if isinstance(primary_entity, dict) and isinstance(primary_entity.get("id"), str) else None
    if not isinstance(primary_entity_id, str) or not primary_entity_id.startswith("entity."):
        return manifest
    primary_entity_slug = primary_entity_id.split(".")[-1]
    related_entity_specs = _ai_coerce_design_related_entities(primary_entity_slug, (design_spec or {}).get("related_entities"))
    if not related_entity_specs:
        return manifest

    app_cfg = manifest.get("app") if isinstance(manifest.get("app"), dict) else {}
    defaults = app_cfg.get("defaults") if isinstance(app_cfg.get("defaults"), dict) else {}
    default_entities = defaults.get("entities") if isinstance(defaults.get("entities"), dict) else {}
    nav = app_cfg.get("nav") if isinstance(app_cfg.get("nav"), list) else []
    nav_group = nav[0] if nav and isinstance(nav[0], dict) else None
    nav_items = nav_group.get("items") if isinstance(nav_group, dict) and isinstance(nav_group.get("items"), list) else []

    manifest_entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    manifest_views = manifest.get("views") if isinstance(manifest.get("views"), list) else []
    manifest_pages = manifest.get("pages") if isinstance(manifest.get("pages"), list) else []
    manifest_actions = manifest.get("actions") if isinstance(manifest.get("actions"), list) else []
    manifest_relations = manifest.get("relations") if isinstance(manifest.get("relations"), list) else []

    primary_form_view = next(
        (
            view
            for view in manifest_views
            if isinstance(view, dict) and view.get("kind") == "form" and view.get("entity") == primary_entity_id
        ),
        None,
    )

    for spec in related_entity_specs:
        entity_slug = spec.get("entity_slug")
        entity_label = spec.get("entity_label")
        if not isinstance(entity_slug, str) or not isinstance(entity_label, str):
            continue
        child_fragment = _build_scaffold_single_entity(module_id, None, entity_slug, entity_label, spec.get("fields") or [], nav_label=spec.get("nav_label"))

        for child_entity in child_fragment.get("entities") if isinstance(child_fragment.get("entities"), list) else []:
            child_entity_id = child_entity.get("id") if isinstance(child_entity, dict) and isinstance(child_entity.get("id"), str) else None
            if isinstance(child_entity_id, str) and not any(isinstance(existing, dict) and existing.get("id") == child_entity_id for existing in manifest_entities):
                manifest_entities.append(copy.deepcopy(child_entity))
        for child_view in child_fragment.get("views") if isinstance(child_fragment.get("views"), list) else []:
            child_view_id = child_view.get("id") if isinstance(child_view, dict) and isinstance(child_view.get("id"), str) else None
            if isinstance(child_view_id, str) and not any(isinstance(existing, dict) and existing.get("id") == child_view_id for existing in manifest_views):
                manifest_views.append(copy.deepcopy(child_view))
        for child_page in child_fragment.get("pages") if isinstance(child_fragment.get("pages"), list) else []:
            child_page_id = child_page.get("id") if isinstance(child_page, dict) and isinstance(child_page.get("id"), str) else None
            if isinstance(child_page_id, str) and not any(isinstance(existing, dict) and existing.get("id") == child_page_id for existing in manifest_pages):
                manifest_pages.append(copy.deepcopy(child_page))
        for child_action in child_fragment.get("actions") if isinstance(child_fragment.get("actions"), list) else []:
            child_action_id = child_action.get("id") if isinstance(child_action, dict) and isinstance(child_action.get("id"), str) else None
            if isinstance(child_action_id, str) and not any(isinstance(existing, dict) and existing.get("id") == child_action_id for existing in manifest_actions):
                manifest_actions.append(copy.deepcopy(child_action))

        child_defaults = (((child_fragment.get("app") or {}).get("defaults") or {}).get("entities") or {}) if isinstance(child_fragment.get("app"), dict) else {}
        for entity_id, page_defaults in child_defaults.items() if isinstance(child_defaults, dict) else []:
            if isinstance(entity_id, str) and entity_id not in default_entities:
                default_entities[entity_id] = copy.deepcopy(page_defaults)

        child_nav_items = (((child_fragment.get("app") or {}).get("nav") or [{}])[0].get("items") or []) if isinstance(child_fragment.get("app"), dict) and isinstance((child_fragment.get("app") or {}).get("nav"), list) else []
        for item in child_nav_items:
            if not isinstance(item, dict):
                continue
            label = item.get("label")
            to = item.get("to")
            if not isinstance(label, str) or not isinstance(to, str):
                continue
            if not any(isinstance(existing, dict) and existing.get("label") == label and existing.get("to") == to for existing in nav_items):
                nav_items.append(copy.deepcopy(item))

        relation = spec.get("relation")
        if isinstance(relation, dict):
            relation_from = relation.get("from")
            relation_to = relation.get("to")
            if (
                isinstance(relation_from, str)
                and isinstance(relation_to, str)
                and not any(isinstance(existing, dict) and existing.get("from") == relation_from and existing.get("to") == relation_to for existing in manifest_relations)
            ):
                manifest_relations.append(copy.deepcopy(relation))

        if isinstance(primary_form_view, dict):
            sections = primary_form_view.get("sections") if isinstance(primary_form_view.get("sections"), list) else []
            related_section_id = spec.get("related_section_id") if isinstance(spec.get("related_section_id"), str) else f"{entity_slug}_related"
            if not any(isinstance(section, dict) and section.get("id") == related_section_id for section in sections):
                sections.append({"id": related_section_id, "title": spec.get("related_title") or entity_label, "fields": []})
                primary_form_view["sections"] = sections

            header = copy.deepcopy(primary_form_view.get("header") if isinstance(primary_form_view.get("header"), dict) else {})
            tabs_cfg = header.get("tabs") if isinstance(header.get("tabs"), dict) else {}
            existing_sections = [section.get("id") for section in sections if isinstance(section, dict) and isinstance(section.get("id"), str)]
            tabs = tabs_cfg.get("tabs") if isinstance(tabs_cfg.get("tabs"), list) else []
            if not tabs:
                tabs = [{"id": "details_tab", "label": "Details", "sections": [section_id for section_id in existing_sections if section_id != related_section_id]}]
                tabs_cfg = {"style": "lifted", "default_tab": "details_tab", "tabs": tabs}
            related_tab_id = spec.get("related_tab_id") if isinstance(spec.get("related_tab_id"), str) else f"{entity_slug}_tab"
            if not any(isinstance(tab, dict) and tab.get("id") == related_tab_id for tab in tabs):
                lookup_field_id = f"{entity_slug}.{primary_entity_slug}_id"
                tabs.append(
                    {
                        "id": related_tab_id,
                        "label": spec.get("related_tab_label") or spec.get("related_title") or entity_label,
                        "sections": [related_section_id],
                        "content": [
                            {
                                "kind": "related_list",
                                "entity_id": f"entity.{entity_slug}",
                                "target": f"view:{entity_slug}.list",
                                "record_domain": {
                                    "op": "eq",
                                    "field": lookup_field_id,
                                    "value": {"ref": "$record.id"},
                                },
                                "create_modal": True,
                                "create_defaults": {
                                    lookup_field_id: {"ref": "$record.id"},
                                },
                            }
                        ],
                    }
                )
            tabs_cfg["tabs"] = tabs
            if not isinstance(tabs_cfg.get("default_tab"), str) or not tabs_cfg.get("default_tab"):
                first_tab = tabs[0].get("id") if tabs and isinstance(tabs[0], dict) else None
                if isinstance(first_tab, str):
                    tabs_cfg["default_tab"] = first_tab
            if not isinstance(tabs_cfg.get("style"), str):
                tabs_cfg["style"] = "lifted"
            header["tabs"] = tabs_cfg
            primary_form_view["header"] = header

    defaults["entities"] = default_entities
    app_cfg["defaults"] = defaults
    if isinstance(nav_group, dict):
        nav_group["items"] = nav_items
    app_cfg["nav"] = nav
    manifest["app"] = app_cfg
    manifest["entities"] = manifest_entities
    manifest["views"] = manifest_views
    manifest["pages"] = manifest_pages
    manifest["actions"] = manifest_actions
    manifest["relations"] = manifest_relations
    return manifest


def _ai_build_design_automation_candidate_ops(module_id: str, manifest: dict, design_spec: dict) -> list[dict]:
    if not isinstance(module_id, str) or not module_id or not isinstance(manifest, dict) or not isinstance(design_spec, dict):
        return []
    entities = [entity for entity in (manifest.get("entities") or []) if isinstance(entity, dict)]
    primary_entity = entities[0] if entities else None
    entity_id = primary_entity.get("id") if isinstance(primary_entity, dict) and isinstance(primary_entity.get("id"), str) else None
    entity_slug = design_spec.get("entity_slug") if isinstance(design_spec.get("entity_slug"), str) else None
    intents = _ai_coerce_design_automation_intents(
        module_id,
        entity_slug or _ai_singularize_slug(module_id),
        [item for item in (design_spec.get("statuses") or []) if isinstance(item, dict)],
        design_spec.get("automation_intents"),
    )
    if not isinstance(entity_id, str) or not entity_id or not intents:
        return []
    module_name = _ai_module_name_from_manifest(module_id, manifest)
    entity_label = _ai_entity_label_from_manifest(manifest, entity_id)
    status_label_map = {
        item.get("value"): item.get("label")
        for item in (design_spec.get("statuses") or [])
        if isinstance(item, dict) and isinstance(item.get("value"), str) and isinstance(item.get("label"), str)
    }
    ops: list[dict] = []
    seen: set[str] = set()
    for intent in intents:
        if not isinstance(intent, dict):
            continue
        intent_id = intent.get("id") if isinstance(intent.get("id"), str) and intent.get("id").strip() else None
        channel = intent.get("channel") if isinstance(intent.get("channel"), str) and intent.get("channel").strip() else "email"
        event = intent.get("event") if isinstance(intent.get("event"), str) and intent.get("event").strip() else None
        recipient = intent.get("recipient") if isinstance(intent.get("recipient"), str) and intent.get("recipient").strip() else None
        if not isinstance(intent_id, str) or not isinstance(event, str):
            continue
        if channel == "email" and not isinstance(recipient, str):
            continue
        if channel == "notify" and (not isinstance(recipient, str) or "{{" in recipient):
            continue
        status_values = [item for item in (intent.get("status_values") or []) if isinstance(item, str) and item.strip()]
        if event == "workflow.status_changed" and not status_values:
            continue
        artifact_id = f"ai_auto_{module_id}_{intent_id}"[:100]
        if artifact_id in seen:
            continue
        seen.add(artifact_id)
        filters: list[dict] = [{"path": "entity_id", "op": "eq", "value": entity_id}]
        if event == "workflow.status_changed":
            filters.append(
                {"path": "to", "op": "eq", "value": status_values[0]}
                if len(status_values) == 1
                else {"path": "to", "op": "in", "value": status_values}
            )
        subject = intent.get("subject") if isinstance(intent.get("subject"), str) and intent.get("subject").strip() else None
        body = intent.get("body") if isinstance(intent.get("body"), str) and intent.get("body").strip() else None
        status_phrase = ", ".join(
            status_label_map.get(value) or _ai_titleize_slug(value)
            for value in status_values
        ) if status_values else None
        if not subject:
            if status_phrase:
                subject = f"{module_name}: {entity_label} reached {status_phrase}"
            elif event == "record.created":
                subject = f"{module_name}: {entity_label} created"
            else:
                subject = f"{module_name}: {entity_label} updated"
        if not body:
            if status_phrase:
                body = (
                    f"A {entity_label.lower()} in {module_name} reached {status_phrase}.\n"
                    f"Record ID: {{{{ trigger.record_id }}}}\n"
                    f"Status: {{{{ trigger.to }}}}"
                )
            elif event == "record.created":
                body = f"A new {entity_label.lower()} was created in {module_name}.\nRecord ID: {{{{ trigger.record_id }}}}"
            else:
                body = f"A {entity_label.lower()} was updated in {module_name}.\nRecord ID: {{{{ trigger.record_id }}}}"
        steps: list[dict] = []
        if isinstance(intent.get("delay_seconds"), int) and intent.get("delay_seconds") > 0:
            steps.append({"id": "step_delay", "kind": "delay", "seconds": intent.get("delay_seconds")})
        if channel == "notify":
            steps.append(
                {
                    "id": "step_send_notify",
                    "kind": "action",
                    "action_id": "system.notify",
                    "inputs": {
                        "recipient_user_ids": recipient,
                        "title": subject,
                        "body": body,
                    },
                }
            )
        else:
            steps.append(
                {
                    "id": "step_send_email",
                    "kind": "action",
                    "action_id": "system.send_email",
                    "inputs": {
                        "to": recipient,
                        "subject": subject,
                        "body_text": body,
                    },
                }
            )
        automation_payload = {
            "name": intent.get("label") if isinstance(intent.get("label"), str) and intent.get("label").strip() else _ai_titleize_slug(intent_id),
            "description": intent.get("description") if isinstance(intent.get("description"), str) and intent.get("description").strip() else f"Draft automation for {module_name}.",
            "status": "draft",
            "trigger": {
                "kind": "event",
                "event_types": [event],
                "filters": filters,
            },
            "steps": steps,
        }
        ops.append(
            {
                "op": "create_automation_record",
                "artifact_type": "automation",
                "artifact_id": artifact_id,
                "automation": automation_payload,
            }
        )
    return ops


def _ai_build_rich_module_scaffold(module_id: str, module_name: str, message: str, design_spec: dict | None = None) -> tuple[dict, str, dict]:
    design_spec = design_spec if isinstance(design_spec, dict) else _ai_generate_module_design_spec(module_id, module_name, message)
    entity_slug = design_spec.get("entity_slug") if isinstance(design_spec.get("entity_slug"), str) else _ai_singularize_slug(module_id)
    entity_label = (
        design_spec.get("entity_label")
        if isinstance(design_spec.get("entity_label"), str) and design_spec.get("entity_label").strip()
        else (module_name.strip() if isinstance(module_name, str) and module_name.strip() else _ai_titleize_slug(entity_slug))
    )
    nav_label = design_spec.get("nav_label") if isinstance(design_spec.get("nav_label"), str) else module_name
    family = design_spec.get("family") if isinstance(design_spec.get("family"), str) else _ai_detect_new_module_family(module_name, message)
    fields = [copy.deepcopy(field) for field in (design_spec.get("fields") or []) if isinstance(field, dict)]
    manifest = _build_scaffold_single_entity(module_id, module_name, entity_slug, entity_label, fields, nav_label=nav_label)
    module_def = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
    if isinstance(design_spec.get("summary"), str) and design_spec.get("summary").strip():
        module_def["description"] = design_spec.get("summary").strip()
        manifest["module"] = module_def
    manifest = _ai_enrich_single_entity_scaffold(manifest, family, message)
    manifest = _ai_apply_design_spec_to_manifest(manifest, design_spec)
    manifest = _ai_add_design_related_entity_scaffolds(manifest, module_id, design_spec)
    if not isinstance(manifest.get("triggers"), list) or not manifest.get("triggers"):
        manifest["triggers"] = _ai_build_module_lifecycle_triggers(manifest, module_id, message)
    return manifest, family, design_spec


def _ai_module_manifest_quality_report(module_id: str, manifest: dict, family: str | None = None, design_spec: dict | None = None) -> dict:
    entities = manifest.get("entities") if isinstance(manifest.get("entities"), list) else []
    entity = entities[0] if entities and isinstance(entities[0], dict) else {}
    entity_slug = _ai_singularize_slug(module_id)
    fields = [field for field in (entity.get("fields") or []) if isinstance(field, dict)]
    views = [view for view in (manifest.get("views") or []) if isinstance(view, dict)]
    pages = [page for page in (manifest.get("pages") or []) if isinstance(page, dict)]
    actions = [action for action in (manifest.get("actions") or []) if isinstance(action, dict) and action.get("kind") == "update_record"]
    workflows = [workflow for workflow in (manifest.get("workflows") or []) if isinstance(workflow, dict)]
    triggers = [trigger for trigger in (manifest.get("triggers") or []) if isinstance(trigger, dict)]
    business_fields = [
        field
        for field in fields
        if isinstance(field.get("id"), str)
        and not field.get("id").endswith(".id")
        and not field.get("id").endswith(".created_at")
        and field.get("id") not in {f"{entity_slug}.status", f"{entity_slug}.owner_id"}
    ]
    view_kinds = sorted(
        {
            view.get("kind")
            for view in views
            if isinstance(view.get("kind"), str) and view.get("kind")
        }
    )
    page_ids = [page.get("id") for page in pages if isinstance(page.get("id"), str)]
    date_fields = [field for field in business_fields if field.get("type") in {"date", "datetime"}]
    form_view = next((view for view in views if view.get("kind") == "form"), {})
    sections = [section for section in (form_view.get("sections") or []) if isinstance(section, dict)]
    issues: list[str] = []
    strengths: list[str] = []
    minimum_business_fields = _ai_design_family_minimum_business_fields(family)
    if len(business_fields) < minimum_business_fields:
        issues.append(f"Create-module draft needs at least {minimum_business_fields} useful fields; found {len(business_fields)}.")
    else:
        strengths.append(f"Provides {len(business_fields)} useful fields.")
    if len(entities) > 1:
        strengths.append(f"Includes {len(entities)} related entities.")
    if "list" not in view_kinds or "form" not in view_kinds:
        issues.append("Create-module draft must include both list and form views.")
    if workflows:
        states = [item for item in (workflows[0].get("states") or []) if isinstance(item, dict)]
        required_action_count = min(4, max(2, len(states) - 1))
        if len(states) >= 3 and len(actions) < required_action_count:
            issues.append(f"Create-module draft has lifecycle states but only {len(actions)} workflow action buttons; expected at least {required_action_count}.")
        if not triggers:
            issues.append("Create-module draft has lifecycle workflow but no trigger surfaces for downstream automations.")
    if date_fields and "calendar" not in view_kinds:
        issues.append("Create-module draft has date tracking but no calendar view.")
    if date_fields and not any(isinstance(page_id, str) and page_id.endswith(".calendar_page") for page_id in page_ids):
        issues.append("Create-module draft has date tracking but no calendar page.")
    if len(business_fields) >= 8 and len(sections) < 2:
        issues.append("Create-module draft should organize the form into multiple sections.")
    if "kanban" in view_kinds:
        strengths.append("Includes kanban workflow view.")
    if triggers:
        strengths.append(f"Includes {len(triggers)} trigger surfaces.")
    if any(isinstance(page_id, str) and page_id.endswith(".calendar_page") for page_id in page_ids):
        strengths.append("Includes a dedicated calendar page.")
    if design_spec and isinstance((design_spec.get("quality") or {}).get("strengths"), list):
        strengths.extend([item for item in (design_spec.get("quality") or {}).get("strengths", []) if isinstance(item, str)])
    return {
        "ok": not issues,
        "issues": issues,
        "strengths": list(dict.fromkeys(strengths)),
        "business_field_count": len(business_fields),
        "entity_count": len(entities),
        "view_kinds": view_kinds,
        "action_count": len(actions),
        "trigger_count": len(triggers),
    }


def _ai_build_new_module_package(module_id: str, module_name: str, message: str) -> dict:
    design_spec = _ai_generate_module_design_spec(module_id, module_name, message)
    manifest, family, design_spec = _ai_build_rich_module_scaffold(module_id, module_name, message, design_spec=design_spec)
    if not isinstance(manifest.get("triggers"), list) or not manifest.get("triggers"):
        manifest["triggers"] = _ai_build_module_lifecycle_triggers(manifest, module_id, message)
    automation_ops = _ai_build_design_automation_candidate_ops(module_id, manifest, design_spec)
    quality = _ai_module_manifest_quality_report(module_id, manifest, family=family, design_spec=design_spec)
    if automation_ops:
        strengths = quality.get("strengths") if isinstance(quality.get("strengths"), list) else []
        strengths.append(f"Includes {len(automation_ops)} draft automation candidates.")
        quality["strengths"] = list(dict.fromkeys([item for item in strengths if isinstance(item, str) and item.strip()]))
    quality["automation_candidate_count"] = len(automation_ops)
    return {
        "manifest": manifest,
        "family": family,
        "design_spec": design_spec,
        "quality": quality,
        "automation_ops": automation_ops,
    }


def _ai_build_create_module_dependency_ops(module_id: str, manifest: dict, module_index: dict[str, dict]) -> list[dict]:
    if not isinstance(module_id, str) or not module_id or not isinstance(manifest, dict) or not isinstance(module_index, dict):
        return []
    declared_required = {
        item.get("module")
        for item in (normalize_depends_on(manifest).get("required") or [])
        if isinstance(item, dict) and isinstance(item.get("module"), str) and item.get("module").strip()
    }
    entity_owners = _dependency_entity_owner_index(module_index)
    dependency_ops: list[dict] = []
    for ref in collect_external_entity_references(manifest):
        entity_id = ref.get("entity_id") if isinstance(ref.get("entity_id"), str) and ref.get("entity_id").strip() else None
        if not isinstance(entity_id, str):
            continue
        owner_module_id = entity_owners.get(entity_id)
        owner_info = module_index.get(owner_module_id) if isinstance(owner_module_id, str) else None
        owner_key = (
            owner_info.get("module_key")
            if isinstance(owner_info, dict) and isinstance(owner_info.get("module_key"), str) and owner_info.get("module_key").strip()
            else owner_module_id
        )
        if not isinstance(owner_key, str) or not owner_key or owner_key == module_id or owner_key in declared_required:
            continue
        owner_manifest = owner_info.get("manifest") if isinstance(owner_info, dict) and isinstance(owner_info.get("manifest"), dict) else {}
        owner_version = (
            owner_info.get("version")
            if isinstance(owner_info, dict) and isinstance(owner_info.get("version"), str) and owner_info.get("version").strip()
            else module_version_from_manifest(owner_manifest)
        )
        dependency = {"module": owner_key}
        if isinstance(owner_version, str) and owner_version.strip():
            dependency["version"] = f">={owner_version.strip()}"
        dependency_ops.append(
            {
                "op": "update_dependency",
                "artifact_type": "module",
                "artifact_id": module_id,
                "kind": "required",
                "dependency": dependency,
            }
        )
        declared_required.add(owner_key)
    return dependency_ops


def _ai_build_create_module_bundle(
    message: str,
    module_ids: list[str],
    module_index: dict[str, dict],
    answer_hints: dict | None = None,
) -> dict | None:
    target_labels = _ai_extract_requested_new_module_labels(message, module_ids, module_index, answer_hints=answer_hints)
    if not target_labels:
        return None

    working_module_index = {
        module_id: copy.deepcopy(info)
        for module_id, info in module_index.items()
        if isinstance(module_id, str) and module_id and isinstance(info, dict)
    }
    candidate_ops: list[dict] = []
    affected_modules: list[str] = []
    dependency_labels: list[str] = []
    requested_change_lines: list[str] = []
    module_details: list[dict] = []

    for module_name in target_labels:
        pending_module_id, pending_manifest = _ai_find_pending_create_module(answer_hints, module_name)
        module_id = pending_module_id or _ai_new_module_id_from_name(module_name, working_module_index)
        scoped_message = _ai_scope_create_module_request(message, module_name)
        automation_ops: list[dict] = []
        if isinstance(pending_manifest, dict):
            manifest = pending_manifest
            design_spec = None
            quality = _ai_module_manifest_quality_report(module_id, manifest)
        else:
            package = _ai_build_new_module_package(module_id, module_name, scoped_message)
            manifest = package.get("manifest")
            design_spec = package.get("design_spec") if isinstance(package.get("design_spec"), dict) else None
            quality = package.get("quality") if isinstance(package.get("quality"), dict) else {}
            automation_ops = [op for op in (package.get("automation_ops") or []) if isinstance(op, dict)]
        if not isinstance(manifest, dict):
            continue
        working_module_index[module_id] = {
            "manifest": copy.deepcopy(manifest),
            "module_key": module_key_from_manifest(manifest) or module_id,
            "version": module_version_from_manifest(manifest),
            "module": {
                "module_id": module_id,
                "name": _module_name_from_manifest(manifest) or module_name,
                "current_hash": None,
            },
        }
        dependency_ops = _ai_build_create_module_dependency_ops(module_id, manifest, working_module_index)
        for op in dependency_ops:
            dependency = op.get("dependency") if isinstance(op.get("dependency"), dict) else {}
            dependency_module = dependency.get("module") if isinstance(dependency.get("module"), str) and dependency.get("module").strip() else None
            if not isinstance(dependency_module, str):
                continue
            dependency_label = _ai_plan_module_label(dependency_module, {"full_selected_artifacts": []})
            if dependency_label not in dependency_labels:
                dependency_labels.append(dependency_label)
        candidate_ops.append(
            {
                "op": "create_module",
                "artifact_type": "module",
                "artifact_id": module_id,
                "manifest": manifest,
                **({"design_spec": design_spec} if isinstance(design_spec, dict) else {}),
                **({"quality_report": quality} if isinstance(quality, dict) else {}),
            }
        )
        candidate_ops.extend(dependency_ops)
        candidate_ops.extend(automation_ops)
        affected_modules.append(module_id)
        interfaces = manifest.get("interfaces") if isinstance(manifest.get("interfaces"), dict) else {}
        included_modes = [
            mode
            for mode in ("list", "kanban", "calendar", "graph")
            if mode in [view.get("kind") for view in (manifest.get("views") or []) if isinstance(view, dict) and isinstance(view.get("kind"), str)]
        ]
        module_details.append(
            {
                "module_name": module_name,
                "module_id": module_id,
                "design_spec": design_spec if isinstance(design_spec, dict) else None,
                "quality": quality if isinstance(quality, dict) else {},
                "workflow_count": len([item for item in (manifest.get("workflows") or []) if isinstance(item, dict)]),
                "stage_action_count": len(
                    [
                        action
                        for action in (manifest.get("actions") or [])
                        if isinstance(action, dict)
                        and action.get("kind") == "update_record"
                        and isinstance(action.get("entity_id"), str)
                    ]
                ),
                "included_modes": included_modes,
                "included_interfaces": [
                    key
                    for key in ("schedulable", "documentable", "dashboardable")
                    if isinstance(interfaces.get(key), list) and interfaces.get(key)
                ],
                "automation_count": len(automation_ops),
            }
        )

    if not candidate_ops or not module_details:
        return None

    advisories: list[str]
    assumptions: list[str]
    if len(module_details) == 1:
        detail = module_details[0]
        assumptions = ["Built a richer starter scaffold based on the module type inferred from the request."]
        included_modes = detail.get("included_modes") if isinstance(detail.get("included_modes"), list) else []
        included_interfaces = detail.get("included_interfaces") if isinstance(detail.get("included_interfaces"), list) else []
        workflow_count = detail.get("workflow_count") if isinstance(detail.get("workflow_count"), int) else 0
        stage_action_count = detail.get("stage_action_count") if isinstance(detail.get("stage_action_count"), int) else 0
        design_spec = detail.get("design_spec") if isinstance(detail.get("design_spec"), dict) else None
        quality = detail.get("quality") if isinstance(detail.get("quality"), dict) else {}
        module_name = detail.get("module_name") if isinstance(detail.get("module_name"), str) and detail.get("module_name").strip() else "this module"
        advisories = [
            f"Starter views included: {', '.join(included_modes)}." if included_modes else "Starter list and form scaffolding were included.",
            "Review the starter fields, statuses, page labels, and view modes before apply.",
        ]
        if workflow_count:
            advisories.append("A starter workflow/status flow was included.")
        if stage_action_count:
            advisories.append("Stage/status actions were included on the form.")
        if included_interfaces:
            advisories.append(f"Interfaces enabled: {', '.join(included_interfaces)}.")
        if dependency_labels:
            advisories.append(f"Required dependencies included: {', '.join(dependency_labels)}.")
        if detail.get("automation_count"):
            advisories.append(f"Draft automation candidates included: {detail['automation_count']}.")
        elif isinstance(design_spec, dict) and (design_spec.get("automation_intents") or []):
            advisories.append("Automation intents were captured in the design blueprint, but concrete recipient/trigger details still need review before draft automation records can be generated.")
        if isinstance(design_spec, dict):
            design_source = design_spec.get("design_source")
            if design_source == "model_primary":
                advisories.append("Design was generated from the model-first module designer, then normalized and validated by OCTO.")
            elif design_source == "deterministic_fallback":
                advisories.append("Model design was unavailable or weaker than fallback, so OCTO used the deterministic starter design.")
        requested_features = _ai_extract_requested_feature_phrases(message)
        if requested_features:
            requested_change_lines.append(f"Include requested capabilities for {', '.join(requested_features[:6])} in {module_name}.")
        for strength in quality.get("strengths") if isinstance(quality.get("strengths"), list) else []:
            if isinstance(strength, str) and strength not in advisories:
                advisories.append(strength)
    else:
        assumptions = ["Split the request into coordinated starter scaffolds for the explicitly named missing modules."]
        module_names = [item.get("module_name") for item in module_details if isinstance(item.get("module_name"), str)]
        advisories = [
            f"Prepared starter scaffolds for {_ai_join_human_list(module_names)}.",
            "Review shared dependencies, cross-module links, and rollout order before apply.",
        ]
        if any(item.get("workflow_count") for item in module_details):
            advisories.append("Starter workflows/status flows were included where they fit naturally.")
        if any(item.get("stage_action_count") for item in module_details):
            advisories.append("Stage/status actions were included on the relevant forms.")
        if dependency_labels:
            advisories.append(f"Required dependencies included: {', '.join(dependency_labels)}.")
        automation_total = sum(item.get("automation_count", 0) for item in module_details if isinstance(item, dict))
        if automation_total:
            advisories.append(f"Draft automation candidates included: {automation_total}.")
        requested_change_lines.append(f"Prepare coordinated starter scaffolds for {_ai_join_human_list(module_names)}.")

    first_detail = module_details[0]
    return {
        "candidate_ops": candidate_ops,
        "assumptions": assumptions,
        "advisories": advisories,
        "requested_change_lines": requested_change_lines,
        "affected_modules": list(dict.fromkeys([module_id for module_id in affected_modules if isinstance(module_id, str) and module_id])),
        "planner_state": {
            "intent": "create_module",
            "module_name": first_detail.get("module_name"),
            "module_id": first_detail.get("module_id"),
            "module_names": [item.get("module_name") for item in module_details if isinstance(item.get("module_name"), str)],
            "module_ids": [item.get("module_id") for item in module_details if isinstance(item.get("module_id"), str)],
        },
    }


def _ai_build_generic_module_scaffold(module_id: str, module_name: str, message: str) -> dict:
    entity_slug = _ai_singularize_slug(module_id)
    entity_label = module_name.strip() if isinstance(module_name, str) and module_name.strip() else _ai_titleize_slug(entity_slug)
    lower = (message or "").lower()
    primary_label = "Title"
    if any(token in lower for token in ("request", "approval", "action", "visit", "log", "register", "pipeline")):
        primary_label = entity_label
    status_options = _ai_extract_status_options(message)
    fields: list[dict] = [
        {"id": f"{entity_slug}.name", "type": "string", "label": primary_label, "required": True},
    ]
    if status_options:
        fields.append(
            {
                "id": f"{entity_slug}.status",
                "type": "enum",
                "label": "Status",
                "default": status_options[0].get("value"),
                "options": status_options,
            }
        )
    if any(token in lower for token in ("date", "schedule", "visit", "run", "event", "meeting", "training", "delivery")):
        fields.append({"id": f"{entity_slug}.date", "type": "date", "label": "Date"})
    fields.append({"id": f"{entity_slug}.owner", "type": "user", "label": "Owner"})
    fields.append({"id": f"{entity_slug}.notes", "type": "text", "label": "Notes"})
    return _build_scaffold_single_entity(module_id, module_name, entity_slug, entity_label, fields, nav_label=module_name)


def _ai_build_new_module_scaffold(module_id: str, module_name: str, message: str) -> dict:
    manifest = None
    family = "generic"
    package = _ai_build_new_module_package(module_id, module_name, message)
    manifest = package.get("manifest")
    family = package.get("family") if isinstance(package.get("family"), str) else family
    if not isinstance(manifest.get("app"), dict) or not isinstance((manifest.get("app") or {}).get("home"), str):
        manifest = _ai_build_generic_module_scaffold(module_id, module_name, message)
    module_def = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
    module_def = copy.deepcopy(module_def)
    module_def["id"] = module_id
    module_def["key"] = module_id
    if not isinstance(module_def.get("name"), str) or not module_def.get("name"):
        module_def["name"] = module_name
    if not isinstance(module_def.get("category"), str) or not module_def.get("category"):
        module_def["category"] = "Custom"
    if not isinstance(module_def.get("icon_key"), str) or not module_def.get("icon_key"):
        module_def["icon_key"] = _ai_design_family_icon_key(family)
    if not isinstance(module_def.get("description"), str) or not module_def.get("description"):
        module_def["description"] = _ai_module_design_summary(module_name, family)
    manifest["module"] = module_def
    if not isinstance(manifest.get("triggers"), list) or not manifest.get("triggers"):
        manifest["triggers"] = _ai_build_module_lifecycle_triggers(manifest, module_id, message)
    return manifest


def _ai_build_latest_style_upgrade_ops(module_id: str, manifest: dict) -> tuple[list[dict], list[str]]:
    if not isinstance(manifest, dict):
        return [], ["Module manifest missing."]
    entities = [entity for entity in (manifest.get("entities") or []) if isinstance(entity, dict)]
    if len(entities) != 1:
        return [], ["This upgrade flow currently supports simple single-entity modules only."]
    entity = entities[0]
    entity_id = entity.get("id")
    if not isinstance(entity_id, str) or not entity_id:
        return [], ["Primary entity could not be resolved."]
    entity_slug = entity_id.split(".")[-1]
    entity_label = entity.get("label") if isinstance(entity.get("label"), str) and entity.get("label").strip() else entity_slug.replace("_", " ").title()
    module_def = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
    module_name = module_def.get("name") if isinstance(module_def.get("name"), str) and module_def.get("name").strip() else module_id
    pages = [page for page in (manifest.get("pages") or []) if isinstance(page, dict)]
    nav_label = None
    for page in pages:
        title = page.get("title")
        if isinstance(title, str) and title.strip():
            nav_label = title.strip()
            break
    current_fields = [
        copy.deepcopy(field)
        for field in (entity.get("fields") or [])
        if isinstance(field, dict) and isinstance(field.get("id"), str) and not str(field.get("id")).endswith(".id")
    ]
    target_manifest = _build_scaffold_single_entity(module_id, module_name, entity_slug, entity_label, current_fields, nav_label=nav_label or entity_label)
    target_module = target_manifest.get("module") if isinstance(target_manifest.get("module"), dict) else {}
    target_module.update({k: v for k, v in module_def.items() if k not in {"id", "key", "name"} and v not in (None, "")})
    target_module["id"] = module_id
    target_module["key"] = module_def.get("key") if isinstance(module_def.get("key"), str) and module_def.get("key").strip() else module_id
    target_module["name"] = module_name
    target_manifest["module"] = target_module

    ops: list[dict] = []
    current_views = {view.get("id"): view for view in (manifest.get("views") or []) if isinstance(view, dict) and isinstance(view.get("id"), str)}
    for target_view in [view for view in (target_manifest.get("views") or []) if isinstance(view, dict) and isinstance(view.get("id"), str)]:
        view_id = target_view.get("id")
        current_view = current_views.get(view_id)
        if current_view is None:
            ops.append({"op": "add_view", "artifact_type": "module", "artifact_id": module_id, "view": target_view})
        elif current_view != target_view:
            ops.append({"op": "update_view", "artifact_type": "module", "artifact_id": module_id, "view_id": view_id, "changes": target_view})

    current_pages = {page.get("id"): page for page in (manifest.get("pages") or []) if isinstance(page, dict) and isinstance(page.get("id"), str)}
    for target_page in [page for page in (target_manifest.get("pages") or []) if isinstance(page, dict) and isinstance(page.get("id"), str)]:
        page_id = target_page.get("id")
        current_page = current_pages.get(page_id)
        if current_page is None:
            ops.append({"op": "add_page", "artifact_type": "module", "artifact_id": module_id, "page": target_page})
        elif current_page != target_page:
            ops.append({"op": "update_page", "artifact_type": "module", "artifact_id": module_id, "page_id": page_id, "changes": target_page})

    current_actions = {action.get("id"): action for action in (manifest.get("actions") or []) if isinstance(action, dict) and isinstance(action.get("id"), str)}
    for target_action in [action for action in (target_manifest.get("actions") or []) if isinstance(action, dict) and isinstance(action.get("id"), str)]:
        action_id = target_action.get("id")
        current_action = current_actions.get(action_id)
        if current_action is None:
            ops.append({"op": "add_action", "artifact_type": "module", "artifact_id": module_id, "action": target_action})
        elif current_action != target_action:
            changes = copy.deepcopy(target_action)
            changes.pop("id", None)
            ops.append({"op": "update_action", "artifact_type": "module", "artifact_id": module_id, "action_id": action_id, "changes": changes})

    return ops, []


def _ai_build_module_lifecycle_triggers(manifest: dict, module_id: str, message: str) -> list[dict]:
    if not isinstance(manifest, dict):
        return []
    entities = [entity for entity in (manifest.get("entities") or []) if isinstance(entity, dict)]
    if not entities:
        return []
    primary_entity = entities[0]
    entity_id = primary_entity.get("id") if isinstance(primary_entity.get("id"), str) and primary_entity.get("id").strip() else None
    if not isinstance(entity_id, str) or not entity_id:
        return []
    triggers: list[dict] = [
        {
            "id": f"{module_id}.record.created",
            "event": "record.created",
            "entity_id": entity_id,
        },
        {
            "id": f"{module_id}.record.updated",
            "event": "record.updated",
            "entity_id": entity_id,
        },
    ]
    workflows = [workflow for workflow in (manifest.get("workflows") or []) if isinstance(workflow, dict)]
    workflow = next((item for item in workflows if item.get("entity") == entity_id and isinstance(item.get("status_field"), str)), None)
    if isinstance(workflow, dict):
        triggers.append(
            {
                "id": f"{module_id}.workflow.status_changed",
                "event": "workflow.status_changed",
                "entity_id": entity_id,
                "status_field": workflow.get("status_field"),
            }
        )
    return triggers


def _parse_manifest_body(body: dict) -> dict | None:
    if not isinstance(body, dict):
        return None
    if "manifest" in body and isinstance(body.get("manifest"), dict):
        return body.get("manifest")
    if "manifest_json" in body and isinstance(body.get("manifest_json"), dict):
        return body.get("manifest_json")
    if "text" in body:
        return None
    return body


def _parse_manifest_text(body: dict) -> dict | None:
    if not isinstance(body, dict):
        return None
    text = body.get("text")
    if not isinstance(text, str):
        return None
    try:
        value = json.loads(text)
    except Exception:
        return None
    return value if isinstance(value, dict) else None


async def _safe_json(request: Request) -> dict:
    try:
        return await request.json()
    except Exception:
        return {}


def _studio2_registry_fingerprint(installed: list[dict]) -> str:
    parts = []
    # Must be tenant-scoped. Otherwise empty/new workspaces can reuse cached studio payloads.
    parts.append(f"org:{get_org_id()}")
    for mod in sorted(installed, key=lambda m: m.get("module_id") or ""):
        module_id = mod.get("module_id") or ""
        current_hash = mod.get("current_hash") or ""
        updated_at = mod.get("updated_at") or ""
        parts.append(f"{module_id}:{current_hash}:{updated_at}")
    digest = hashlib.sha256("|".join(parts).encode("utf-8")).hexdigest()
    return f"sha256:{digest}"


def _studio2_extract_view_ids_from_blocks(blocks: list) -> list[str]:
    view_ids: set[str] = set()
    ordered_view_ids: list[str] = []

    def _add_view_id(target) -> None:
        if not isinstance(target, str) or not target:
            return
        normalized = target.split("view:", 1)[1] if target.startswith("view:") else target
        if normalized and normalized not in view_ids:
            view_ids.add(normalized)
            ordered_view_ids.append(normalized)

    def visit(block) -> None:
        if not isinstance(block, dict):
            return
        kind = block.get("kind")
        if kind == "view":
            _add_view_id(block.get("target"))
        elif kind == "view_modes":
            modes = block.get("modes")
            default_mode = block.get("default_mode") if isinstance(block.get("default_mode"), str) else None
            if isinstance(modes, list):
                # Prefer the default_mode target first for page bootstrap.
                if default_mode:
                    for mode in modes:
                        if not isinstance(mode, dict):
                            continue
                        if mode.get("mode") == default_mode:
                            _add_view_id(mode.get("target"))
                            break
                for mode in modes:
                    if not isinstance(mode, dict):
                        continue
                    _add_view_id(mode.get("target"))
        for key in ("content",):
            nested = block.get(key)
            if isinstance(nested, list):
                for item in nested:
                    visit(item)
        items = block.get("items")
        if isinstance(items, list):
            for item in items:
                if isinstance(item, dict):
                    content = item.get("content")
                    if isinstance(content, list):
                        for child in content:
                            visit(child)
        tabs = block.get("tabs")
        if isinstance(tabs, list):
            for tab in tabs:
                if isinstance(tab, dict):
                    content = tab.get("content")
                    if isinstance(content, list):
                        for child in content:
                            visit(child)

    for block in blocks or []:
        visit(block)
    return ordered_view_ids


def _resolve_bootstrap_view(manifest: dict, page_id: str | None, view_id: str | None) -> tuple[dict | None, dict | None]:
    views = manifest.get("views") if isinstance(manifest, dict) else None
    pages = manifest.get("pages") if isinstance(manifest, dict) else None
    view_obj = None
    page_obj = None
    resolved_view_id = None
    if isinstance(view_id, str) and view_id:
        resolved_view_id = view_id.split("view:", 1)[1] if view_id.startswith("view:") else view_id
    if resolved_view_id and isinstance(views, list):
        view_obj = next((v for v in views if isinstance(v, dict) and v.get("id") == resolved_view_id), None)
    if isinstance(page_id, str) and page_id and isinstance(pages, list):
        page_obj = next((p for p in pages if isinstance(p, dict) and p.get("id") == page_id), None)
        if page_obj and not view_obj:
            content = page_obj.get("content")
            view_ids = _studio2_extract_view_ids_from_blocks(content if isinstance(content, list) else [])
            if view_ids and isinstance(views, list):
                view_obj = next((v for v in views if isinstance(v, dict) and v.get("id") == view_ids[0]), None)
    return view_obj, page_obj


def _fallback_view_id_from_page_id(manifest: dict, page_id: str | None) -> str | None:
    if not isinstance(page_id, str) or not page_id:
        return None
    views = manifest.get("views") if isinstance(manifest, dict) else None
    if not isinstance(views, list):
        return None
    suffix = None
    base = page_id
    if page_id.endswith(".list_page"):
        base = page_id.replace(".list_page", "")
        suffix = ".list"
    elif page_id.endswith(".form_page"):
        base = page_id.replace(".form_page", "")
        suffix = ".form"
    elif page_id.endswith("_list_page"):
        base = page_id.replace("_list_page", "")
        suffix = ".list"
    elif page_id.endswith("_form_page"):
        base = page_id.replace("_form_page", "")
        suffix = ".form"
    candidates = []
    if suffix:
        candidates.extend([f"{base}{suffix}", f"{base}s{suffix}", f"{base}es{suffix}"])
        candidates.extend([f"entity.{base}{suffix}", f"entity.{base}s{suffix}", f"entity.{base}es{suffix}"])
    for view in views:
        if not isinstance(view, dict):
            continue
        view_id = view.get("id")
        if not isinstance(view_id, str):
            continue
        if view_id in candidates:
            return view_id
    return None


def _studio2_compact_manifest(manifest: dict) -> dict:
    entities_payload = []
    for entity in manifest.get("entities", []) if isinstance(manifest.get("entities"), list) else []:
        if not isinstance(entity, dict):
            continue
        fields_payload = []
        for field in entity.get("fields", []) if isinstance(entity.get("fields"), list) else []:
            if not isinstance(field, dict):
                continue
            fields_payload.append(
                {
                    "id": field.get("id"),
                    "type": field.get("type"),
                    "label": field.get("label"),
                }
            )
        entities_payload.append(
            {
                "id": entity.get("id"),
                "display_field": entity.get("display_field"),
                "fields": fields_payload,
            }
        )

    views_payload = []
    for view in manifest.get("views", []) if isinstance(manifest.get("views"), list) else []:
        if not isinstance(view, dict):
            continue
        views_payload.append(
            {
                "id": view.get("id"),
                "kind": view.get("kind") or view.get("type"),
                "entity_id": view.get("entity") or view.get("entity_id") or view.get("entityId"),
            }
        )

    pages_payload = []
    for page in manifest.get("pages", []) if isinstance(manifest.get("pages"), list) else []:
        if not isinstance(page, dict):
            continue
        view_ids = set()
        header = page.get("header") if isinstance(page.get("header"), dict) else None
        if header and isinstance(header.get("actions"), list):
            for action in header.get("actions") or []:
                if not isinstance(action, dict):
                    continue
                target = action.get("target")
                if isinstance(target, str) and target.startswith("view:"):
                    view_ids.add(target.split("view:", 1)[1])
        content = page.get("content")
        if isinstance(content, list):
            view_ids.update(_studio2_extract_view_ids_from_blocks(content))
        pages_payload.append(
            {
                "id": page.get("id"),
                "title": page.get("title"),
                "view_ids": sorted(view_ids),
            }
        )

    actions_payload = []
    for action in manifest.get("actions", []) if isinstance(manifest.get("actions"), list) else []:
        if not isinstance(action, dict):
            continue
        actions_payload.append(
            {
                "id": action.get("id"),
                "kind": action.get("kind"),
                "entity_id": action.get("entity_id") or action.get("entity"),
            }
        )

    relations_payload = []
    for rel in manifest.get("relations", []) if isinstance(manifest.get("relations"), list) else []:
        if not isinstance(rel, dict):
            continue
        relations_payload.append({"from": rel.get("from"), "to": rel.get("to")})

    return {
        "entities": entities_payload,
        "views": views_payload,
        "pages": pages_payload,
        "actions": actions_payload,
        "relations": relations_payload,
    }


def _studio2_trim_manifest_payload(manifest: dict, max_bytes: int) -> tuple[dict, bool]:
    payload = copy.deepcopy(manifest)
    try:
        if len(json.dumps(payload, separators=(",", ":")).encode("utf-8")) <= max_bytes:
            return payload, False
    except Exception:
        pass
    truncated_keys = []
    for key in ("entities", "views", "pages", "actions", "relations", "workflows"):
        items = payload.get(key)
        if isinstance(items, list) and len(items) > 20:
            payload[key] = items[:20]
            truncated_keys.append(key)
    payload["_truncated"] = True
    if truncated_keys:
        payload["_truncated_keys"] = truncated_keys
    return payload, True


def _studio2_read_manifest_payload(request: Request, module_id: str, level: str | None) -> dict:
    module, manifest = _get_installed_manifest(request, module_id)
    if not module or not manifest:
        return {
            "ok": False,
            "error": {"code": "MODULE_NOT_FOUND", "message": "Module not installed or manifest missing"},
            "module_id": module_id,
        }
    level_norm = level if level in {"summary", "full"} else "summary"
    if level_norm == "summary":
        payload = _studio2_compact_manifest(manifest)
        return {"ok": True, "module_id": module_id, "level": "summary", "manifest": payload, "truncated": False}
    trimmed, truncated = _studio2_trim_manifest_payload(manifest, STUDIO2_READ_MANIFEST_MAX_BYTES)
    return {"ok": True, "module_id": module_id, "level": "full", "manifest": trimmed, "truncated": truncated}


def _studio2_build_registry_snapshot(request: Request) -> dict:
    installed = _get_registry_list(request)
    fingerprint = _studio2_registry_fingerprint(installed)
    cached = _cache_get("studio2_registry", fingerprint)
    if cached is not None:
        return cached

    manifest_by_id: dict[str, dict] = {}
    if USE_DB:
        with get_conn() as conn:
            rows = fetch_all(
                conn,
                """
                select m.module_id, m.name, m.current_hash, m.updated_at, s.manifest
                from modules_installed m
                join manifest_snapshots s
                  on s.org_id=m.org_id
                 and s.module_id=m.module_id
                 and s.manifest_hash=m.current_hash
                where m.org_id=%s
                """,
                [get_org_id()],
                query_name="studio2.registry.snapshot",
            )
        for row in rows:
            mid = row.get("module_id")
            manifest = row.get("manifest")
            if isinstance(manifest, str):
                try:
                    manifest = json.loads(manifest)
                except Exception:
                    manifest = None
            if isinstance(mid, str) and isinstance(manifest, dict):
                manifest_by_id[mid] = manifest

    modules_payload = []
    for mod in installed:
        module_id = mod.get("module_id")
        if not module_id:
            continue
        manifest = manifest_by_id.get(module_id)
        if manifest is None:
            head = mod.get("current_hash")
            if isinstance(head, str):
                try:
                    manifest = _get_snapshot(request, module_id, head)
                except Exception:
                    manifest = None
        if not isinstance(manifest, dict):
            continue
        module_section = manifest.get("module") if isinstance(manifest.get("module"), dict) else {}
        name = module_section.get("name") or mod.get("name")
        version = module_section.get("version")
        compact = _studio2_compact_manifest(manifest)
        modules_payload.append(
            {
                "module_id": module_id,
                "name": name,
                "version": version,
                "updated_at": mod.get("updated_at"),
                **compact,
            }
        )

    payload = {"snapshot_hash": fingerprint, "modules": modules_payload}
    _cache_set("studio2_registry", payload, fingerprint)
    return payload


def _studio2_list_modules(request: Request) -> dict:
    installed = _get_registry_list(request)
    drafts_list = drafts.list_drafts()
    drafts_by_id = {d.get("module_id"): d for d in drafts_list if isinstance(d, dict)}
    dep_index = _dependency_manifest_index(request)
    def _draft_name(draft_row: dict | None) -> str | None:
        if not isinstance(draft_row, dict):
            return None
        manifest = draft_row.get("manifest")
        if not isinstance(manifest, dict):
            return None
        manifest = _sanitize_manifest(manifest)
        module_section = manifest.get("module") if isinstance(manifest.get("module"), dict) else None
        name = module_section.get("name") if isinstance(module_section, dict) else None
        return name if isinstance(name, str) and name.strip() else None

    items = []
    for mod in installed:
        module_id = mod.get("module_id")
        draft = drafts_by_id.get(module_id)
        draft_name = _draft_name(draft)
        draft_manifest = draft.get("manifest") if isinstance(draft, dict) and isinstance(draft.get("manifest"), dict) else None
        draft_hash = _draft_hash(draft_manifest, module_id=module_id) if isinstance(draft_manifest, dict) else None
        current_hash = mod.get("current_hash")
        dep_info = dep_index.get(module_id) if isinstance(module_id, str) else None
        module_key = dep_info.get("module_key") if isinstance(dep_info, dict) else None
        items.append(
            {
                "module_id": module_id,
                "module_key": module_key or module_id,
                "name": draft_name or mod.get("name") or module_id,
                "installed": True,
                "enabled": mod.get("enabled"),
                "current_hash": current_hash,
                "updated_at": mod.get("updated_at"),
                "draft_hash": draft_hash,
                "draft_in_sync": bool(draft_hash and isinstance(current_hash, str) and draft_hash == current_hash),
                "draft": {
                    "updated_at": draft.get("updated_at") if isinstance(draft, dict) else None,
                    "updated_by": draft.get("updated_by") if isinstance(draft, dict) else None,
                    "base_snapshot_id": draft.get("base_snapshot_id") if isinstance(draft, dict) else None,
                }
                if isinstance(draft, dict)
                else None,
            }
        )
    for draft in drafts_list:
        module_id = draft.get("module_id")
        if not module_id or any(item["module_id"] == module_id for item in items):
            continue
        draft_name = _draft_name(draft)
        draft_manifest = draft.get("manifest") if isinstance(draft.get("manifest"), dict) else None
        draft_hash = _draft_hash(draft_manifest, module_id=module_id) if isinstance(draft_manifest, dict) else None
        module_key = module_key_from_manifest(draft_manifest) if isinstance(draft_manifest, dict) else None
        items.append(
            {
                "module_id": module_id,
                "module_key": module_key or module_id,
                "name": draft_name or module_id,
                "installed": False,
                "enabled": False,
                "current_hash": None,
                "updated_at": None,
                "draft_hash": draft_hash,
                "draft_in_sync": False,
                "draft": {
                    "updated_at": draft.get("updated_at"),
                    "updated_by": draft.get("updated_by"),
                    "base_snapshot_id": draft.get("base_snapshot_id"),
                },
            }
        )
    return {"modules": items}


def _decode_segment(segment: str) -> str:
    return segment.replace("~1", "/").replace("~0", "~")


def _parse_pointer(pointer: str) -> list[str]:
    if pointer == "":
        return []
    parts = pointer.split("/")
    if parts and parts[0] == "":
        parts = parts[1:]
    return [_decode_segment(p) for p in parts]


def _get_container_and_token(doc: Any, pointer: str):
    tokens = _parse_pointer(pointer)
    if not tokens:
        return (None, "")
    current = doc
    for token in tokens[:-1]:
        if isinstance(current, dict):
            if token not in current:
                raise KeyError("Missing object key")
            current = current[token]
        elif isinstance(current, list):
            if not token.isdigit():
                raise IndexError("Invalid list index")
            idx = int(token)
            if idx < 0 or idx >= len(current):
                raise IndexError("List index out of range")
            current = current[idx]
        else:
            raise TypeError("Cannot traverse into non-container")
    return current, tokens[-1]


def _get_value(doc: Any, pointer: str) -> Any:
    tokens = _parse_pointer(pointer)
    current = doc
    for token in tokens:
        if isinstance(current, dict):
            if token not in current:
                raise KeyError("Missing object key")
            current = current[token]
        elif isinstance(current, list):
            if not token.isdigit():
                raise IndexError("Invalid list index")
            idx = int(token)
            if idx < 0 or idx >= len(current):
                raise IndexError("List index out of range")
            current = current[idx]
        else:
            raise TypeError("Cannot traverse into non-container")
    return current


def _pointer_exists(doc: Any, pointer: str) -> bool:
    try:
        _get_value(doc, pointer)
        return True
    except Exception:
        return False


def _apply_add(doc: Any, path: str, value: Any) -> None:
    if path == "":
        raise ValueError("Cannot add at document root")
    container, token = _get_container_and_token(doc, path)
    if isinstance(container, dict):
        container[token] = value
        return
    if isinstance(container, list):
        if token == "-":
            container.append(value)
            return
        if not token.isdigit():
            raise IndexError("Invalid list index")
        idx = int(token)
        if idx < 0 or idx > len(container):
            raise IndexError("List index out of range")
        container.insert(idx, value)
        return
    raise TypeError("Cannot add into non-container")


def _apply_remove(doc: Any, path: str) -> None:
    container, token = _get_container_and_token(doc, path)
    if isinstance(container, dict):
        if token not in container:
            raise KeyError("Missing object key")
        del container[token]
        return
    if isinstance(container, list):
        if not token.isdigit():
            raise IndexError("Invalid list index")
        idx = int(token)
        if idx < 0 or idx >= len(container):
            raise IndexError("List index out of range")
        del container[idx]
        return
    raise TypeError("Cannot remove from non-container")


def _apply_replace(doc: Any, path: str, value: Any) -> None:
    if path == "":
        raise ValueError("Cannot replace document root")
    container, token = _get_container_and_token(doc, path)
    if isinstance(container, dict):
        if token not in container:
            raise KeyError("Missing object key")
        container[token] = value
        return
    if isinstance(container, list):
        if not token.isdigit():
            raise IndexError("Invalid list index")
        idx = int(token)
        if idx < 0 or idx >= len(container):
            raise IndexError("List index out of range")
        container[idx] = value
        return
    raise TypeError("Cannot replace in non-container")


def _apply_ops(doc: Any, ops: list[dict]) -> None:
    for op in ops:
        name = op.get("op")
        if name == "add":
            _apply_add(doc, op["path"], op["value"])
        elif name == "remove":
            _apply_remove(doc, op["path"])
        elif name == "replace":
            _apply_replace(doc, op["path"], op["value"])
        else:
            raise ValueError("Unsupported op")


def _studio2_diff_summary(ops: list[dict]) -> dict:
    counts: dict[str, int] = {"add": 0, "remove": 0, "replace": 0}
    touched = []
    for op in ops:
        name = op.get("op")
        if name in counts:
            counts[name] += 1
        path = op.get("path")
        if isinstance(path, str):
            touched.append(path)
    return {"counts": counts, "touched": sorted(set(touched))}


def _studio2_build_patchset_from_manifest(module_id: str, base_manifest: dict, target_manifest: dict) -> dict:
    base_keys = set(base_manifest.keys()) if isinstance(base_manifest, dict) else set()
    target_keys = set(target_manifest.keys()) if isinstance(target_manifest, dict) else set()
    keys = sorted(base_keys | target_keys)
    ops: list[dict] = []
    for key in keys:
        path = f"/{_encode_pointer_token(str(key))}"
        if key not in target_keys:
            ops.append({"op": "remove", "path": path})
            continue
        value = target_manifest.get(key)
        if key not in base_keys:
            ops.append({"op": "add", "path": path, "value": value})
        else:
            ops.append({"op": "set", "path": path, "value": value})
    return {
        "patchset_id": f"ps_{uuid.uuid4().hex}",
        "summary": "Apply manifest draft",
        "patches": [{"module_id": module_id, "ops": ops}],
    }


def _encode_pointer_token(token: str) -> str:
    return token.replace("~", "~0").replace("/", "~1")


def _find_entity_ref_paths(node: Any, old_ids: set[str], path: str = "") -> list[str]:
    matches: list[str] = []
    if isinstance(node, dict):
        for key, value in node.items():
            next_path = f"{path}/{_encode_pointer_token(str(key))}"
            if key in {"entity", "entity_id", "entityId"} and isinstance(value, str) and value in old_ids:
                matches.append(next_path)
            matches.extend(_find_entity_ref_paths(value, old_ids, next_path))
        return matches
    if isinstance(node, list):
        for idx, value in enumerate(node):
            next_path = f"{path}/{idx}"
            matches.extend(_find_entity_ref_paths(value, old_ids, next_path))
    return matches


def _studio2_resolve_ops(manifest: dict, ops: list[dict]) -> tuple[list[dict], list[dict]]:
    errors: list[dict] = []
    resolved_ops: list[dict] = []
    rename_entities: list[tuple[str, str]] = []
    for idx, op in enumerate(ops):
        if not isinstance(op, dict):
            errors.append({"code": "OP_INVALID", "message": "op must be object", "path": f"ops[{idx}]"})
            continue
        name = op.get("op")
        if name is None:
            if isinstance(op.get("add"), dict):
                payload = op.get("add")
                op = {"op": "add", "path": payload.get("path"), "value": payload.get("value")}
                name = "add"
            elif isinstance(op.get("set"), dict):
                payload = op.get("set")
                op = {"op": "set", "path": payload.get("path"), "value": payload.get("value")}
                name = "set"
            elif isinstance(op.get("remove"), dict):
                payload = op.get("remove")
                op = {"op": "remove", "path": payload.get("path")}
                name = "remove"
            elif isinstance(op.get("rename_id"), dict):
                payload = op.get("rename_id")
                op = {"op": "rename_id", "path": payload.get("path"), "value": payload.get("value")}
                name = "rename_id"
        path = op.get("path")
        if name not in {"set", "add", "remove", "rename_id"}:
            errors.append({"code": "OP_UNSUPPORTED", "message": f"unsupported op {name}", "path": f"ops[{idx}].op"})
            continue
        if not isinstance(path, str) or not path.startswith("/"):
            errors.append({"code": "OP_PATH_INVALID", "message": "path must be JSON pointer", "path": f"ops[{idx}].path"})
            continue
        if name == "remove":
            resolved_ops.append({"op": "remove", "path": path})
            continue
        value = op.get("value")
        if name in {"set", "add", "rename_id"} and value is None:
            errors.append({"code": "OP_VALUE_REQUIRED", "message": "value is required", "path": f"ops[{idx}].value"})
            continue
        if name == "rename_id":
            try:
                current = _get_value(manifest, path)
            except Exception:
                current = None
            if isinstance(current, dict):
                old_id = current.get("id") if isinstance(current.get("id"), str) else None
                if old_id and isinstance(value, str) and (path.startswith("/entities/") or old_id.startswith("entity.")):
                    rename_entities.append((old_id, value))
                resolved_ops.append({"op": "replace", "path": f"{path}/id", "value": value})
            else:
                if isinstance(current, str) and isinstance(value, str) and (path.startswith("/entities/") or current.startswith("entity.")):
                    rename_entities.append((current, value))
                resolved_ops.append({"op": "replace", "path": path, "value": value})
            continue
        if name == "add":
            resolved_ops.append({"op": "add", "path": path, "value": value})
            continue
        if name == "set":
            op_name = "replace" if _pointer_exists(manifest, path) else "add"
            resolved_ops.append({"op": op_name, "path": path, "value": value})
            continue
    if rename_entities:
        replaced: dict[str, str] = {}
        for old_id, new_id in rename_entities:
            if not isinstance(old_id, str) or not isinstance(new_id, str) or old_id == new_id:
                continue
            full_new = new_id if new_id.startswith("entity.") else f"entity.{new_id}"
            old_ids = {old_id}
            if old_id.startswith("entity."):
                old_ids.add(old_id[7:])
            else:
                old_ids.add(f"entity.{old_id}")
            for path in _find_entity_ref_paths(manifest, old_ids):
                replaced[path] = full_new
        for path in sorted(replaced):
            resolved_ops.append({"op": "replace", "path": path, "value": replaced[path]})
    return resolved_ops, errors


def _studio2_apply_patchset(manifest: dict, patchset: dict) -> dict:
    patches = patchset.get("patches", []) if isinstance(patchset, dict) else []
    if not isinstance(patches, list) or len(patches) != 1:
        return {
            "ok": False,
            "errors": [{"code": "PATCHSET_INVALID", "message": "single patch required", "path": "patches"}],
            "warnings": [],
            "resolved_ops": [],
            "manifest": None,
        }
    patch = patches[0]
    ops = patch.get("ops")
    if not isinstance(ops, list):
        return {
            "ok": False,
            "errors": [{"code": "PATCHSET_INVALID", "message": "ops must be list", "path": "patches[0].ops"}],
            "warnings": [],
            "resolved_ops": [],
            "manifest": None,
        }
    resolved_ops, errors = _studio2_resolve_ops(manifest, ops)
    if errors:
        return {"ok": False, "errors": errors, "warnings": [], "resolved_ops": resolved_ops, "manifest": None}
    updated = json.loads(json.dumps(manifest))
    try:
        _apply_ops(updated, resolved_ops)
    except Exception as exc:
        return {
            "ok": False,
            "errors": [{"code": "PATCH_APPLY_FAILED", "message": str(exc), "path": "patches[0].ops"}],
            "warnings": [],
            "resolved_ops": resolved_ops,
            "manifest": None,
        }
    return {"ok": True, "errors": [], "warnings": [], "resolved_ops": resolved_ops, "manifest": updated}


def _json_fix_attempt(text: str, line: int | None, col: int | None) -> tuple[str | None, list[str]]:
    suggestions: list[str] = []

    def can_parse(candidate: str) -> bool:
        try:
            json.loads(candidate)
            return True
        except Exception:
            return False

    if can_parse(text):
        return text, suggestions

    cleaned = re.sub(r",\s*([}\]])", r"\1", text)
    if cleaned != text:
        suggestions.append("removed trailing commas")
    if can_parse(cleaned):
        return cleaned, suggestions

    fixed = cleaned
    open_braces = fixed.count("{")
    close_braces = fixed.count("}")
    open_brackets = fixed.count("[")
    close_brackets = fixed.count("]")
    if open_braces > close_braces:
        fixed = fixed + ("}" * (open_braces - close_braces))
        suggestions.append("added missing closing braces")
    if open_brackets > close_brackets:
        fixed = fixed + ("]" * (open_brackets - close_brackets))
        suggestions.append("added missing closing brackets")
    if can_parse(fixed):
        return fixed, suggestions

    if line and col:
        lines = fixed.splitlines()
        if 1 <= line <= len(lines):
            idx = 0
            for i, l in enumerate(lines, start=1):
                if i == line:
                    idx += max(col - 1, 0)
                    break
                idx += len(l) + 1
            if 0 <= idx <= len(fixed):
                if idx > 0 and fixed[idx - 1] not in "{[,": 
                    candidate = fixed[:idx] + "," + fixed[idx:]
                    suggestions.append("inserted missing comma")
                    if can_parse(candidate):
                        return candidate, suggestions

    return None, suggestions


def _preview_module_change(request: Request, module_id: str, manifest: dict, reason: str, patch_id: str, mode: str) -> dict:
    head = _get_head(request, module_id)
    if mode == "upgrade" and head is None:
        return {"error": _error_response("MODULE_NOT_INSTALLED", "Module not installed", "module_id", status=404)}
    actor = getattr(request.state, "actor", None)
    actor_id = actor.get("user_id") if isinstance(actor, dict) else "anonymous"
    payload = _preview_payload(
        module_id,
        head,
        manifest,
        reason,
        patch_id,
        actor_id,
    )
    payload["mode"] = mode
    return payload


def _apply_module_change_db(module_id: str, manifest: dict, actor: dict | None, mode: str, reason: str, patch_id: str | None) -> dict:
    existing = registry.get(module_id)
    warnings = []
    if mode == "install":
        if existing is not None:
            warnings.append({"code": "MODULE_ALREADY_INSTALLED", "message": "Module already installed", "path": "module_id", "detail": None})
            return {"ok": True, "errors": [], "warnings": warnings, "module": existing, "audit_id": None}
        new_hash = store.init_module(module_id, manifest, actor=actor, reason=reason)
        module_name = _module_name_from_manifest(manifest)
        with get_conn() as conn:
            version = _insert_module_version(conn, module_id, new_hash, manifest, actor, notes=reason)
            execute(
                conn,
                """
                insert into modules_installed (org_id, module_id, enabled, current_hash, name, installed_at, updated_at, tags, status, active_version, last_error, archived)
                values (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,%s)
                """,
                [get_org_id(), module_id, True, new_hash, module_name, _now(), _now(), None, "installed", version.get("version_id"), None, False],
                query_name="modules_installed.insert_install",
            )
            audit_id = str(uuid.uuid4())
            audit = {
                "audit_id": audit_id,
                "module_id": module_id,
                "action": "install",
                "from_hash": None,
                "to_hash": new_hash,
                "patch_id": patch_id,
                "actor": actor,
                "reason": reason,
                "at": _now(),
            }
            execute(
                conn,
                """
                insert into module_audit (org_id, module_id, audit_id, audit, created_at)
                values (%s,%s,%s,%s,%s)
                """,
                [get_org_id(), module_id, audit_id, json.dumps(audit, default=str), _now()],
                query_name="module_audit.insert_install",
            )
        return {"ok": True, "errors": [], "warnings": warnings, "module": registry.get(module_id), "audit_id": audit_id}

    result = _upgrade_module_db(module_id, manifest, actor=actor, reason=reason, patch_id=patch_id)
    return result


def _apply_module_change_memory(module_id: str, manifest: dict, actor: dict | None, mode: str, reason: str, patch_id: str | None) -> dict:
    existing = registry.get(module_id)
    warnings = []
    if mode == "install" and existing is not None:
        warnings.append({"code": "MODULE_ALREADY_INSTALLED", "message": "Module already installed", "path": "module_id", "detail": None})
        return {"ok": True, "errors": [], "warnings": warnings, "module": existing, "audit_id": None}

    new_hash = store.init_module(module_id, manifest, actor=actor, reason=reason)
    now = _now()
    prev_hash = existing.get("current_hash") if existing else None
    if existing is None:
        record = {
            "module_id": module_id,
            "name": _module_name_from_manifest(manifest),
            "enabled": True,
            "current_hash": new_hash,
            "installed_at": now,
            "updated_at": now,
            "tags": None,
        }
    else:
        record = dict(existing)
        record["current_hash"] = new_hash
        record["updated_at"] = now
        module_name = _module_name_from_manifest(manifest)
        if module_name:
            record["name"] = module_name
        if mode == "install":
            record["enabled"] = True
    # In-memory registry does not expose a public setter, so we update internals here.
    registry._modules[module_id] = record
    audit_id = str(uuid.uuid4())
    audit = {
        "audit_id": audit_id,
        "module_id": module_id,
        "action": mode,
        "from_hash": prev_hash,
        "to_hash": new_hash,
        "patch_id": patch_id,
        "actor": actor,
        "reason": reason,
        "at": now,
    }
    registry._audit.setdefault(module_id, []).insert(0, audit)
    return {"ok": True, "errors": [], "warnings": warnings, "module": record, "audit_id": audit_id}


def _apply_module_change(request: Request, module_id: str, manifest: dict, mode: str, reason: str, patch_id: str | None) -> dict:
    dep_errors, dep_warnings = _validate_dependency_state(request, module_id, manifest, mode)
    if dep_errors:
        return {"ok": False, "errors": dep_errors, "warnings": dep_warnings, "module": None, "audit_id": None}
    actor = getattr(request.state, "actor", None)
    if USE_DB:
        result = _apply_module_change_db(module_id, manifest, actor=actor, mode=mode, reason=reason, patch_id=patch_id)
    else:
        result = _apply_module_change_memory(module_id, manifest, actor=actor, mode=mode, reason=reason, patch_id=patch_id)
    if dep_warnings:
        result["warnings"] = (result.get("warnings") or []) + dep_warnings
    return result


def _marketplace_slugify(text: str) -> str:
    base = re.sub(r"[^a-z0-9]+", "-", (text or "").strip().lower()).strip("-")
    return base or "app"


def _marketplace_unique_slug(conn, slug: str, row_id: str | None = None) -> str:
    candidate = _marketplace_slugify(slug)
    idx = 2
    while True:
        if row_id:
            row = fetch_one(
                conn,
                "select id from marketplace_apps where slug=%s and id<>%s limit 1",
                [candidate, row_id],
                query_name="marketplace.slug.exists_update",
            )
        else:
            row = fetch_one(
                conn,
                "select id from marketplace_apps where slug=%s limit 1",
                [candidate],
                query_name="marketplace.slug.exists",
            )
        if not row:
            return candidate
        candidate = f"{_marketplace_slugify(slug)}-{idx}"
        idx += 1


def _normalize_marketplace_row(row: dict | None) -> dict | None:
    if not isinstance(row, dict):
        return None
    manifest = row.get("source_manifest")
    if isinstance(manifest, str):
        try:
            manifest = json.loads(manifest)
        except Exception:
            manifest = {}
    manifest_version = manifest.get("manifest_version") if isinstance(manifest, dict) else None
    module_def = manifest.get("module") if isinstance(manifest, dict) else None
    module_def = module_def if isinstance(module_def, dict) else {}
    module_version = module_def.get("version")
    return {
        "id": row.get("id"),
        "slug": row.get("slug"),
        "title": row.get("title"),
        "description": row.get("description"),
        "category": row.get("category"),
        "icon_url": row.get("icon_url"),
        "status": row.get("status"),
        "source_org_id": row.get("source_org_id"),
        "source_module_id": row.get("source_module_id"),
        "source_manifest_hash": row.get("source_manifest_hash"),
        "manifest_version": manifest_version if isinstance(manifest_version, str) else None,
        "module_version": module_version if isinstance(module_version, str) else None,
        "source_manifest": manifest if isinstance(manifest, dict) else {},
        "published_by_user_id": row.get("published_by_user_id"),
        "created_at": row.get("created_at"),
        "updated_at": row.get("updated_at"),
    }


def _generate_cloned_module_id(source_module_id: str) -> str:
    slug = _marketplace_slugify(source_module_id or "module")
    if slug.startswith("module-"):
        slug = slug[7:]
    slug = slug.replace("-", "_")
    slug = re.sub(r"[^a-z0-9_]+", "", slug)
    slug = (slug or "app")[:20]
    return f"module_{slug}_{uuid.uuid4().hex[:6]}"


def _delete_module_db(module_id: str, actor: dict | None, reason: str, force: bool = False, archive: bool = False) -> dict:
    record = registry.get(module_id)
    if record is None:
        return {"ok": False, "errors": [{"code": "MODULE_NOT_FOUND", "message": "module not found", "path": "module_id", "detail": None}], "warnings": [], "module": None, "audit_id": None}
    if module_id in SYSTEM_MODULE_IDS:
        return {"ok": False, "errors": [{"code": "MODULE_DELETE_FORBIDDEN", "message": "System module cannot be deleted", "path": "module_id", "detail": None}], "warnings": [], "module": None, "audit_id": None}

    manifest = None
    manifest_hash = record.get("current_hash")
    if manifest_hash:
        try:
            manifest = store.get_snapshot(module_id, manifest_hash)
        except Exception:
            manifest = None

    entity_ids = collect_entity_record_ids(manifest or {})
    audit_id = str(uuid.uuid4())
    audit = {
        "audit_id": audit_id,
        "module_id": module_id,
        "action": "module_archived" if archive else "module_deleted",
        "from_hash": record.get("current_hash"),
        "to_hash": None,
        "patch_id": None,
        "actor": actor,
        "reason": "archive" if archive else reason,
        "at": _now(),
    }
    with get_conn() as conn:
        record_count = 0
        entity_counts: dict[str, int] = {}
        if entity_ids:
            placeholders = ",".join(["%s"] * len(entity_ids))
            rows = fetch_all(
                conn,
                f"""
                select entity_id, count(*) as count
                from records_generic
                where tenant_id=%s and entity_id in ({placeholders})
                group by entity_id
                """,
                [get_org_id(), *sorted(entity_ids)],
                query_name="records_generic.count_module_entities",
            )
            for row in rows:
                entity_id = row.get("entity_id")
                if not isinstance(entity_id, str):
                    continue
                count = int(row.get("count") or 0)
                if count:
                    entity_counts[entity_id] = count
                    record_count += count
        if record_count > 0 and not force and not archive:
            return {
                "ok": False,
                "errors": [
                    {
                        "code": "MODULE_HAS_RECORDS",
                        "message": "Module has records; delete blocked unless forced",
                        "path": "module_id",
                        "detail": {"record_count": record_count, "entity_counts": entity_counts},
                    }
                ],
                "warnings": [],
                "module": None,
                "audit_id": None,
            }
        if force and entity_ids:
            placeholders = ",".join(["%s"] * len(entity_ids))
            execute(
                conn,
                f"delete from records_generic where tenant_id=%s and entity_id in ({placeholders})",
                [get_org_id(), *sorted(entity_ids)],
                query_name="records_generic.delete_module_entities",
            )
        execute(conn, "delete from module_drafts where org_id=%s and module_id=%s", [get_org_id(), module_id], query_name="module_drafts.delete")
        execute(conn, "delete from module_draft_versions where module_id=%s", [module_id], query_name="module_draft_versions.delete")
        execute(
            conn,
            """
            update modules_installed
            set archived=true, enabled=false, status=%s, updated_at=%s
            where org_id=%s and module_id=%s
            """,
            ["archived", _now(), get_org_id(), module_id],
            query_name="modules_installed.archive",
        )
        execute(
            conn,
            """
            insert into module_audit (org_id, module_id, audit_id, audit, created_at)
            values (%s,%s,%s,%s,%s)
            """,
            [get_org_id(), module_id, audit_id, json.dumps(audit, default=str), _now()],
            query_name="module_audit.insert_delete",
        )
    return {"ok": True, "errors": [], "warnings": [], "module": None, "audit_id": audit_id}


def _delete_module_memory(module_id: str, actor: dict | None, reason: str, force: bool = False, archive: bool = False) -> dict:
    return delete_module_memory(
        module_id,
        registry,
        store,
        generic_records,
        drafts=drafts,
        actor=actor,
        reason=reason,
        force=force,
        archive=archive,
    )


@app.get("/modules")
async def list_modules(request: Request) -> dict:
    cached = _cache_get("modules")
    if cached is not None:
        return {"modules": cached}
    modules = _get_registry_list(request)
    for mod in modules:
        # Fill missing display metadata from the current manifest snapshot.
        # modules_installed stores the operational state; the manifest is the source of truth for app meta.
        need_meta = not (
            (isinstance(mod.get("name"), str) and mod.get("name").strip())
            and (isinstance(mod.get("description"), str) and mod.get("description").strip())
            and (isinstance(mod.get("category"), str) and mod.get("category").strip())
            and (isinstance(mod.get("module_version"), str) and mod.get("module_version").strip())
        )
        if not need_meta:
            continue
        module_id = mod.get("module_id")
        manifest_hash = mod.get("current_hash")
        if not module_id or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        module_def = manifest.get("module") if isinstance(manifest, dict) else None
        module_def = module_def if isinstance(module_def, dict) else {}
        if not (isinstance(mod.get("name"), str) and mod.get("name").strip()):
            name = _module_name_from_manifest(manifest) or module_def.get("name")
            if isinstance(name, str) and name.strip():
                mod["name"] = name.strip()
        if not (isinstance(mod.get("description"), str) and mod.get("description").strip()):
            desc = module_def.get("description")
            if isinstance(desc, str) and desc.strip():
                mod["description"] = desc.strip()
        if not (isinstance(mod.get("category"), str) and mod.get("category").strip()):
            cat = module_def.get("category")
            if isinstance(cat, str) and cat.strip():
                mod["category"] = cat.strip()
        if not (isinstance(mod.get("module_version"), str) and mod.get("module_version").strip()):
            ver = module_def.get("version")
            if isinstance(ver, str) and ver.strip():
                mod["module_version"] = ver.strip()
        if not (isinstance(mod.get("icon_key"), str) and mod.get("icon_key").strip()):
            icon_key = module_def.get("icon_key") or module_def.get("icon")
            if isinstance(icon_key, str) and icon_key.strip():
                mod["icon_key"] = icon_key.strip()
        if not (isinstance(mod.get("module_key"), str) and mod.get("module_key").strip()):
            stable_key = module_def.get("key") if isinstance(module_def.get("key"), str) else module_def.get("id")
            if isinstance(stable_key, str) and stable_key.strip():
                mod["module_key"] = stable_key.strip()
    _cache_set("modules", modules)
    return {"modules": modules}


def _dependency_status_for_module(module_id: str, manifest_index: dict[str, dict]) -> dict:
    info = manifest_index.get(module_id)
    manifest = info.get("manifest") if isinstance(info, dict) else {}
    deps = normalize_depends_on(manifest if isinstance(manifest, dict) else {})
    available_versions = {}
    available_enabled = {}
    for _, data in manifest_index.items():
        key = data.get("module_key")
        if not isinstance(key, str) or not key:
            continue
        available_versions[key] = data.get("version")
        available_enabled[key] = bool(data.get("enabled"))
    required = []
    for item in deps.get("required", []):
        dep_module = item.get("module")
        if not isinstance(dep_module, str):
            continue
        constraint = item.get("version")
        actual = available_versions.get(dep_module)
        installed = dep_module in available_versions
        enabled = bool(available_enabled.get(dep_module)) if installed else False
        required.append(
            {
                "module": dep_module,
                "constraint": constraint,
                "installed": installed,
                "enabled": enabled,
                "actual_version": actual,
                "version_ok": True if not installed else (True if not isinstance(constraint, str) else version_satisfies_constraint(actual, constraint)),
            }
        )
    optional = []
    for item in deps.get("optional", []):
        dep_module = item.get("module")
        if not isinstance(dep_module, str):
            continue
        constraint = item.get("version")
        actual = available_versions.get(dep_module)
        installed = dep_module in available_versions
        enabled = bool(available_enabled.get(dep_module)) if installed else False
        optional.append(
            {
                "module": dep_module,
                "constraint": constraint,
                "installed": installed,
                "enabled": enabled,
                "actual_version": actual,
            }
        )
    return {"required": required, "optional": optional}


@app.get("/modules/{module_id}/dependencies")
async def module_dependencies(module_id: str, request: Request) -> dict:
    actor = getattr(request.state, "actor", None)
    denied = _require_capability(actor, "modules.manage", "Admin role required")
    if denied:
        return denied
    module = _get_module(request, module_id)
    if not isinstance(module, dict):
        return _error_response("MODULE_NOT_INSTALLED", "Module not installed", "module_id", status=404)
    manifest_index = _dependency_manifest_index(request)
    if module_id not in manifest_index:
        return _error_response("MODULE_NOT_INSTALLED", "Module manifest missing", "module_id", status=404)
    manifests_by_key = {}
    for _, data in manifest_index.items():
        key = data.get("module_key")
        if not isinstance(key, str) or not key:
            continue
        manifests_by_key[key] = data.get("manifest") or {}
    graph = build_dependency_graph(manifests_by_key)
    reverse = build_reverse_dependents(graph)
    cycle = find_cycle(graph)
    dep_state = _dependency_status_for_module(module_id, manifest_index)
    module_key = manifest_index[module_id].get("module_key") if isinstance(manifest_index.get(module_id), dict) else module_id
    return _ok_response(
        {
            "module_id": module_id,
            "module_key": module_key,
            "dependencies": dep_state,
            "dependents": reverse.get(module_key, []),
            "cycle_detected": bool(cycle),
            "cycle": cycle,
        }
    )


@app.get("/modules/{module_id}/dependents")
async def module_dependents(module_id: str, request: Request) -> dict:
    actor = getattr(request.state, "actor", None)
    denied = _require_capability(actor, "modules.manage", "Admin role required")
    if denied:
        return denied
    manifest_index = _dependency_manifest_index(request)
    if module_id not in manifest_index:
        return _error_response("MODULE_NOT_INSTALLED", "Module not installed", "module_id", status=404)
    graph = build_dependency_graph({mid: data.get("manifest") or {} for mid, data in manifest_index.items()})
    reverse = build_reverse_dependents(graph)
    return _ok_response({"module_id": module_id, "dependents": reverse.get(module_id, [])})


@app.post("/modules/dependencies/resolve")
async def resolve_module_dependencies(request: Request) -> dict:
    actor = getattr(request.state, "actor", None)
    denied = _require_capability(actor, "modules.manage", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    module_ids = body.get("module_ids") if isinstance(body, dict) else None
    manifest_index = _dependency_manifest_index(request)
    available_ids = sorted(manifest_index.keys())
    selected_ids: list[str]
    if module_ids is None:
        selected_ids = available_ids
    elif isinstance(module_ids, list) and all(isinstance(mid, str) and mid for mid in module_ids):
        selected_ids = sorted(set(module_ids))
    else:
        return _error_response("MODULE_DEPENDENCY_INVALID", "module_ids must be a list of module ids", "module_ids", status=400)
    missing = [mid for mid in selected_ids if mid not in manifest_index]
    if missing:
        return _error_response("MODULE_NOT_INSTALLED", "One or more modules are not installed", "module_ids", {"missing": missing}, status=400)
    graph = build_dependency_graph({mid: data.get("manifest") or {} for mid, data in manifest_index.items()}, module_ids=selected_ids)
    cycle = find_cycle(graph)
    order = [] if cycle else topological_install_order(graph)
    reverse = build_reverse_dependents(graph)
    return _ok_response({"module_ids": selected_ids, "graph": graph, "order": order, "cycle": cycle, "dependents": reverse})


@app.get("/marketplace/apps")
async def list_marketplace_apps(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    include_non_published = bool(actor.get("platform_role") == "superadmin")
    with get_conn() as conn:
        rows = fetch_all(
            conn,
            """
            select id, slug, title, description, category, icon_url, status,
                   source_org_id, source_module_id, source_manifest_hash, source_manifest,
                   published_by_user_id, created_at, updated_at
            from marketplace_apps
            where (%s or status='published')
            order by created_at desc
            """,
            [include_non_published],
            query_name="marketplace.list",
        )
    items = []
    for row in rows:
        normalized = _normalize_marketplace_row(row)
        if not normalized:
            continue
        normalized.pop("source_manifest", None)
        items.append(normalized)
    return _ok_response({"apps": items})


@app.post("/marketplace/apps/publish")
async def publish_marketplace_app(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    if actor.get("platform_role") != "superadmin":
        return _error_response("FORBIDDEN", "Superadmin role required", status=403)
    body = await _safe_json(request)
    module_id = body.get("module_id") if isinstance(body, dict) else None
    if not isinstance(module_id, str) or not module_id.strip():
        return _error_response("MODULE_REQUIRED", "module_id is required", "module_id", status=400)
    module, manifest = _get_installed_manifest(request, module_id)
    if module is None or manifest is None:
        return _error_response("MODULE_NOT_FOUND", "Module not installed", "module_id", status=404)
    source_hash = module.get("current_hash")
    if not isinstance(source_hash, str) or not source_hash:
        return _error_response("MODULE_INVALID", "Module snapshot hash missing", "module_id", status=400)
    module_meta = manifest.get("module") if isinstance(manifest, dict) else {}
    module_meta = module_meta if isinstance(module_meta, dict) else {}
    default_title = module.get("name") or (module_meta.get("name") if isinstance(module_meta, dict) else None) or module_id
    title = body.get("title") if isinstance(body, dict) else None
    title = title.strip() if isinstance(title, str) and title.strip() else default_title
    description = body.get("description") if isinstance(body, dict) and isinstance(body.get("description"), str) else None
    if description is None and isinstance(module_meta.get("description"), str):
        description = module_meta.get("description")
    category = body.get("category") if isinstance(body, dict) and isinstance(body.get("category"), str) else None
    if category is None and isinstance(module_meta.get("category"), str):
        category = module_meta.get("category")
    icon_url = body.get("icon_url") if isinstance(body, dict) and isinstance(body.get("icon_url"), str) else None
    if icon_url is None:
        icon_url = module.get("icon_key")
    if icon_url is None:
        icon_url = module_meta.get("icon_key") or module_meta.get("icon") or module_meta.get("icon_url")
    if category is not None:
        category = category.strip() or None
    if description is not None:
        description = description.strip() or None
    if icon_url is not None:
        icon_url = icon_url.strip() or None
    slug_input = body.get("slug") if isinstance(body, dict) and isinstance(body.get("slug"), str) and body.get("slug").strip() else title
    org_id = get_org_id()
    with get_conn() as conn:
        existing = fetch_one(
            conn,
            """
            select id
            from marketplace_apps
            where source_org_id=%s and source_module_id=%s and source_manifest_hash=%s
            limit 1
            """,
            [org_id, module_id, source_hash],
            query_name="marketplace.get_by_source",
        )
        if existing:
            listing_id = existing.get("id")
            slug = _marketplace_unique_slug(conn, slug_input, row_id=listing_id)
            row = fetch_one(
                conn,
                """
                update marketplace_apps
                set slug=%s, title=%s, description=%s, category=%s, icon_url=%s,
                    status='published', source_manifest=%s, updated_at=%s
                where id=%s
                returning id, slug, title, description, category, icon_url, status,
                          source_org_id, source_module_id, source_manifest_hash, source_manifest,
                          published_by_user_id, created_at, updated_at
                """,
                [slug, title, description, category, icon_url, json.dumps(manifest), _now(), listing_id],
                query_name="marketplace.update",
            )
        else:
            slug = _marketplace_unique_slug(conn, slug_input)
            row = fetch_one(
                conn,
                """
                insert into marketplace_apps (
                  slug, title, description, category, icon_url, status,
                  source_org_id, source_module_id, source_manifest_hash, source_manifest,
                  published_by_user_id, created_at, updated_at
                )
                values (%s,%s,%s,%s,%s,'published',%s,%s,%s,%s,%s,%s,%s)
                returning id, slug, title, description, category, icon_url, status,
                          source_org_id, source_module_id, source_manifest_hash, source_manifest,
                          published_by_user_id, created_at, updated_at
                """,
                [
                    slug,
                    title,
                    description,
                    category,
                    icon_url,
                    org_id,
                    module_id,
                    source_hash,
                    json.dumps(manifest),
                    actor.get("user_id"),
                    _now(),
                    _now(),
                ],
                query_name="marketplace.insert",
            )
    listing = _normalize_marketplace_row(row) or {}
    listing.pop("source_manifest", None)
    return _ok_response({"app": listing})


@app.post("/marketplace/apps/{app_id}/clone")
async def clone_marketplace_app(request: Request, app_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "modules.manage", "Admin role required")
    if denied:
        return denied
    body = await _safe_json(request)
    with get_conn() as conn:
        row = fetch_one(
            conn,
            """
            select id, slug, title, description, category, icon_url, status,
                   source_org_id, source_module_id, source_manifest_hash, source_manifest,
                   published_by_user_id, created_at, updated_at
            from marketplace_apps
            where id=%s
            limit 1
            """,
            [app_id],
            query_name="marketplace.get",
        )
    listing = _normalize_marketplace_row(row)
    if not listing:
        return _error_response("MARKETPLACE_APP_NOT_FOUND", "Marketplace app not found", "app_id", status=404)
    if listing.get("status") != "published":
        return _error_response("MARKETPLACE_APP_UNAVAILABLE", "Marketplace app is not published", "app_id", status=400)
    source_manifest = listing.get("source_manifest")
    if not isinstance(source_manifest, dict):
        return _error_response("MARKETPLACE_APP_INVALID", "Marketplace app manifest missing", "app_id", status=400)
    requested_module_id = body.get("module_id") if isinstance(body, dict) else None
    if isinstance(requested_module_id, str) and requested_module_id.strip():
        new_module_id = requested_module_id.strip()
        if not _is_valid_module_id(new_module_id):
            return _error_response("MODULE_INVALID", "Invalid module_id format", "module_id", status=400)
    else:
        new_module_id = _generate_cloned_module_id(listing.get("source_module_id") or "module")
    while registry.get(new_module_id):
        new_module_id = _generate_cloned_module_id(listing.get("source_module_id") or "module")
    cloned_manifest = copy.deepcopy(source_manifest)
    if not isinstance(cloned_manifest.get("module"), dict):
        cloned_manifest["module"] = {}
    cloned_manifest["module"]["id"] = new_module_id
    requested_name = body.get("name") if isinstance(body, dict) and isinstance(body.get("name"), str) else None
    if isinstance(requested_name, str) and requested_name.strip():
        cloned_manifest["module"]["name"] = requested_name.strip()
    elif not cloned_manifest["module"].get("name"):
        cloned_manifest["module"]["name"] = listing.get("title") or new_module_id
    patch_id = f"marketplace_clone:{listing.get('id')}"
    result = _apply_module_change(
        request,
        new_module_id,
        cloned_manifest,
        mode="install",
        reason=f"marketplace clone from {listing.get('source_module_id')}",
        patch_id=patch_id,
    )
    if not result.get("ok"):
        first = (result.get("errors") or [{}])[0]
        return _error_response(
            first.get("code") or "MODULE_CLONE_FAILED",
            first.get("message") or "Failed to clone app",
            first.get("path"),
            first.get("detail"),
            status=400,
        )
    # Default installs from marketplace should be disabled so the admin can review/configure before users see it.
    with get_conn() as conn:
        execute(
            conn,
            "update modules_installed set enabled=false, updated_at=%s where org_id=%s and module_id=%s",
            [_now(), get_org_id(), new_module_id],
            query_name="modules_installed.disable_after_marketplace_clone",
        )
        icon_key = listing.get("icon_url")
        if isinstance(icon_key, str) and icon_key.strip():
            execute(
                conn,
                "update modules_installed set icon_key=%s, updated_at=%s where org_id=%s and module_id=%s",
                [icon_key.strip(), _now(), get_org_id(), new_module_id],
                query_name="modules_installed.set_icon_after_marketplace_clone",
            )
    _cache_invalidate("modules")
    _cache_invalidate("registry_list")
    _cache_invalidate("manifest")
    _cache_invalidate("studio_modules")
    _compiled_cache_invalidate(new_module_id)
    return _ok_response(
        {
            "module": result.get("module"),
            "module_id": new_module_id,
            "audit_id": result.get("audit_id"),
            "marketplace_app_id": listing.get("id"),
        },
        warnings=result.get("warnings") or [],
    )


@app.post("/marketplace/apps/{app_id}/status")
async def set_marketplace_app_status(request: Request, app_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    if actor.get("platform_role") != "superadmin":
        return _error_response("FORBIDDEN", "Superadmin role required", status=403)
    body = await _safe_json(request)
    status = body.get("status") if isinstance(body, dict) else None
    if not isinstance(status, str) or status.strip() not in {"draft", "published", "archived"}:
        return _error_response("STATUS_INVALID", "status must be draft, published, or archived", "status", status=400)
    status = status.strip()
    with get_conn() as conn:
        row = fetch_one(
            conn,
            """
            update marketplace_apps
            set status=%s, updated_at=%s
            where id=%s
            returning id, slug, title, description, category, icon_url, status,
                      source_org_id, source_module_id, source_manifest_hash, source_manifest,
                      published_by_user_id, created_at, updated_at
            """,
            [status, _now(), app_id],
            query_name="marketplace.status.update",
        )
    listing = _normalize_marketplace_row(row)
    if not listing:
        return _error_response("MARKETPLACE_APP_NOT_FOUND", "Marketplace app not found", "app_id", status=404)
    listing.pop("source_manifest", None)
    return _ok_response({"app": listing})


