@app.patch("/email/connections/{connection_id}")
async def update_email_connection(request: Request, connection_id: str) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    denied = _require_capability(actor, "templates.manage", "Email templates permission required")
    if denied:
        return denied
    conn = connection_store.get(connection_id)
    if not conn or conn.get("type") != "smtp":
        return _error_response("CONNECTION_NOT_FOUND", "Connection not found", "connection_id", status=404)
    body = await _safe_json(request)
    if not isinstance(body, dict):
        return _error_response("INVALID_BODY", "Expected JSON object", None, status=400)
    updates = {}
    if "name" in body:
        name = body.get("name")
        if not isinstance(name, str) or not name.strip():
            return _error_response("NAME_REQUIRED", "name is required", "name", status=400)
        updates["name"] = name.strip()
    if "status" in body:
        st = body.get("status")
        if not isinstance(st, str) or st not in {"active", "disabled"}:
            return _error_response("STATUS_INVALID", "status must be active or disabled", "status", status=400)
        updates["status"] = st
    if "config" in body:
        config = body.get("config")
        if config is not None and not isinstance(config, dict):
            return _error_response("CONFIG_INVALID", "config must be an object", "config", status=400)
        updates["config"] = config or {}
    if "secret_ref" in body:
        secret_ref, secret_err = _validated_secret_ref(body.get("secret_ref"))
        if secret_err:
            return secret_err
        updates["secret_ref"] = secret_ref
    if "secret_refs" in body:
        secret_refs, secret_refs_err = _validated_secret_refs(body.get("secret_refs"))
        if secret_refs_err:
            return secret_refs_err
        updates["secret_refs"] = secret_refs or {}
    updated = connection_store.update(connection_id, updates) if hasattr(connection_store, "update") else None
    if not updated:
        updated = connection_store.get(connection_id)
    return _ok_response({"connection": updated})


@app.get("/templates/meta")
async def templates_meta(request: Request) -> dict:
    actor = _resolve_actor(request)
    if isinstance(actor, JSONResponse):
        return actor
    org_id = actor.get("workspace_id") or "default"
    cache_key = f"templates_meta:{org_id}"
    cached = _resp_cache_get(cache_key)
    if cached is not None:
        logger.info("cache_hit=templates_meta key=%s", cache_key)
        return cached
    entities: list[dict] = []
    for mod in _get_registry_list(request):
        if not mod.get("enabled"):
            continue
        module_id = mod.get("module_id")
        manifest_hash = mod.get("current_hash")
        if not module_id or not manifest_hash:
            continue
        try:
            manifest = _get_snapshot(request, module_id, manifest_hash)
        except Exception:
            continue
        for ent in manifest.get("entities", []) if isinstance(manifest.get("entities"), list) else []:
            if not isinstance(ent, dict):
                continue
            ent_id = ent.get("id")
            if not isinstance(ent_id, str) or not ent_id:
                continue
            entities.append(
                {
                    "id": ent_id,
                    "label": ent.get("label") or ent.get("name") or ent_id,
                    "module_id": module_id,
                    "module_name": mod.get("name"),
                }
            )
    response = _ok_response({"entities": entities})
    _resp_cache_set(cache_key, response)
    logger.info("cache_miss=templates_meta key=%s", cache_key)
    return response


def _validation_payload(errors: list[dict], undefined: set[str], warnings: list[str], possible_undefined: set[str] | None = None) -> dict:
    return {
        "compiled_ok": not errors,
        "errors": errors,
        "undefined": sorted(undefined),
        "possible_undefined": sorted(possible_undefined or set()),
        "warnings": warnings,
        "validated_at": _now(),
    }


def _build_template_warnings(subject: str | None, body_html: str | None, body_text: str | None) -> list[str]:
    warnings: list[str] = []
    if subject is not None and not str(subject).strip():
        warnings.append("subject is empty")
    if body_html is not None and not str(body_html).strip():
        warnings.append("body_html is empty")
    if body_text is not None and not str(body_text).strip():
        warnings.append("body_text is empty")
    return warnings


def _html_to_text(html: str | None) -> str:
    if not html:
        return ""
    import re
    text = re.sub(r"<[^>]+>", " ", html)
    return re.sub(r"\s+", " ", text).strip()


